/** Pre-fill the AI Generator tab from the current exam's details */
function ebAIPrefillFromExam() {
  const subject   = document.getElementById('eb-subject')?.value?.trim() || '';
  const classLevel= document.getElementById('eb-classLevel')?.value?.trim() || '';
  const examType  = document.getElementById('eb-examType')?.value?.trim() || '';

  const aiSubject = document.getElementById('ebai-subject');
  const aiTopic   = document.getElementById('ebai-topic');
  const aiNotes   = document.getElementById('ebai-notes');

  if (aiSubject && subject) aiSubject.value = subject;
  if (aiTopic)   aiTopic.value = classLevel ? `${subject} — ${classLevel}` : subject;
  if (aiNotes && examType) aiNotes.placeholder = `Paste syllabus notes for ${examType} exam...`;

  showToast('Fields pre-filled from your exam details <i class="fa-solid fa-check"></i>', 'success');
}

/** Quick-jump to AI tab from the exam builder wizard (called by inline button) */
function ebQuickAI() {
  ebAIPrefillFromExam();
  const aiTabBtn = document.querySelector('#ebTabBar .tb[onclick*="tabEBAIGen"]');
  if (aiTabBtn) openEBTab('tabEBAIGen', aiTabBtn);
}

/** Auto-generate instructions using AI */
const _origEbAutoInstructions = window.ebAutoInstructions;
window.ebAutoInstructions = async function() {
  const subject   = document.getElementById('eb-subject')?.value?.trim() || 'General';
  const examType  = document.getElementById('eb-examType')?.value?.trim() || 'Midterm';
  const classLevel= document.getElementById('eb-classLevel')?.value?.trim() || '';
  const duration  = document.getElementById('eb-duration')?.value?.trim() || '2 hours';

  const btn = document.querySelector('[onclick="ebAutoInstructions()"]');
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Generating...'; }

  try {
    const system = 'You are an expert Kenyan curriculum exam paper writer. Respond ONLY with valid JSON: {"instructions":["instruction1","instruction2",...]}. Generate 5-7 clear, professional exam instructions.';
    const prompt = `Generate exam instructions for: Subject: ${subject}, Class: ${classLevel}, Type: ${examType}, Duration: ${duration}. Include instructions about: answering all questions, time management, writing clearly, no cheating, and any subject-specific guidance.`;
    const text = await ebCallClaude(prompt, system);
    const clean = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
    const parsed = JSON.parse(clean);
    const list = document.getElementById('ebInstructionsList');
    if (list && parsed.instructions) {
      list.innerHTML = '';
      parsed.instructions.forEach(inst => {
        const div = document.createElement('div');
        div.className = 'eb-inst-item';
        div.innerHTML = `<input type="text" placeholder="Add instruction..." class="eb-inst-input" value="${inst.replace(/"/g,'&quot;')}"/><button class="btn btn-sm" style="padding:4px 8px;color:var(--danger)" onclick="this.closest('.eb-inst-item').remove()"><i class="fa-solid fa-xmark"></i></button>`;
        list.appendChild(div);
      });
      showToast(`Generated ${parsed.instructions.length} instructions <i class="fa-solid fa-check"></i>`, 'success');
    }
  } catch(err) {
    showToast('AI failed: ' + err.message, 'error');
    // Fall back to original
    if (typeof _origEbAutoInstructions === 'function') _origEbAutoInstructions();
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = ' Auto-Generate'; }
  }
};


// ══════════════════════════════════════════════════════
// FLOATING CONTACT BUTTONS
// ══════════════════════════════════════════════════════
const K_CONTACT = 'ei_contact_settings';

function loadContactSettings() {
  try { return JSON.parse(localStorage.getItem(K_CONTACT)) || {}; } catch { return {}; }
}

function saveContactSettingsData(data) {
  localStorage.setItem(K_CONTACT, JSON.stringify(data));
}

function platSaveContactSettings() {
  const whatsapp = (document.getElementById('contactWhatsappNum') || {}).value?.trim() || '';
  const facebook = (document.getElementById('contactFacebookUrl') || {}).value?.trim() || '';
  const call     = (document.getElementById('contactCallNum')     || {}).value?.trim() || '';
  const whatsappEnabled = !!(document.getElementById('contactWhatsappEnabled') || {}).checked;
  const facebookEnabled = !!(document.getElementById('contactFacebookEnabled') || {}).checked;
  const callEnabled     = !!(document.getElementById('contactCallEnabled')     || {}).checked;
  saveContactSettingsData({ whatsapp, facebook, call, whatsappEnabled, facebookEnabled, callEnabled });
  initFloatingContact();
  const st = document.getElementById('platContactStatus');
  if (st) { st.innerHTML = '<i class="fa-solid fa-circle-check"></i> Saved!'; st.style.color = '#16a34a'; setTimeout(() => { st.textContent = ''; }, 2500); }
}

function platLoadContactInputs() {
  const cfg = loadContactSettings();
  const set = (id, val) => { const el = document.getElementById(id); if (el) el.value = val || ''; };
  set('contactWhatsappNum', cfg.whatsapp);
  set('contactFacebookUrl', cfg.facebook);
  set('contactCallNum',     cfg.call);
  const setChk = (id, val) => { const el = document.getElementById(id); if (el) el.checked = !!val; };
  setChk('contactWhatsappEnabled', cfg.whatsappEnabled);
  setChk('contactFacebookEnabled', cfg.facebookEnabled);
  setChk('contactCallEnabled',     cfg.callEnabled);
}

function initFloatingContact() {
  const cfg = loadContactSettings();
  const wrap = document.getElementById('floatingContact');
  if (!wrap) return;

  const hasAny = (cfg.whatsapp && cfg.whatsappEnabled) || (cfg.facebook && cfg.facebookEnabled) || (cfg.call && cfg.callEnabled);
  wrap.style.display = hasAny ? 'flex' : 'none';

  // WhatsApp
  const wa = document.getElementById('fcWhatsapp');
  if (wa) {
    if (cfg.whatsapp && cfg.whatsappEnabled) {
      const num = cfg.whatsapp.replace(/\D/g, '');
      wa.href = 'https://wa.me/' + num;
      wa.style.display = 'flex';
    } else {
      wa.style.display = 'none';
    }
  }

  // Facebook
  const fb = document.getElementById('fcFacebook');
  if (fb) {
    if (cfg.facebook && cfg.facebookEnabled) {
      fb.href = cfg.facebook;
      fb.style.display = 'flex';
    } else {
      fb.style.display = 'none';
    }
  }

  // Call
  const cl = document.getElementById('fcCall');
  if (cl) {
    if (cfg.call && cfg.callEnabled) {
      cl.href = 'tel:' + cfg.call.replace(/\s/g, '');
      cl.style.display = 'flex';
    } else {
      cl.style.display = 'none';
    }
  }
}

// Auto-populate admin inputs when platform section is opened
(function() {
  const _origGo = typeof go === 'function' ? go : null;
  // Hook into the section navigation
  document.addEventListener('DOMContentLoaded', function() {
    initFloatingContact();
    // Populate inputs whenever platform section becomes visible
    const platSection = document.getElementById('s-platform');
    if (platSection && window.MutationObserver) {
      const obs = new MutationObserver(() => {
        if (platSection.style.display !== 'none' && !platSection.hidden) {
          platLoadContactInputs();
        }
      });
      obs.observe(platSection, { attributes: true, attributeFilter: ['style', 'class'] });
    }
  });
})();

