const LC_SETTINGS_KEY  = 'ei_chat_settings';
const LC_MSG_KEY       = id => 'ei_chat_msgs_' + id;  // school support msgs
const LC_COMMUNITY_KEY = 'ei_community_msgs';
const LC_UNREAD_KEY    = id => 'ei_chat_unread_' + id;

let _lcActiveSchool = null;
let _lcTab = 'support';
let _lcPollTimer = null;
let _fchatOpen = false;

function lcGetSettings() {
  try { return JSON.parse(localStorage.getItem(LC_SETTINGS_KEY)) || {}; } catch { return {}; }
}
function lcSaveSettings(cfg) { localStorage.setItem(LC_SETTINGS_KEY, JSON.stringify(cfg)); }

function platSaveChatSettings() {
  const live = !!(document.getElementById('chatLiveEnabled')||{}).checked;
  const community = !!(document.getElementById('chatCommunityEnabled')||{}).checked;
  lcSaveSettings({ liveEnabled: live, communityEnabled: community });
  lcUpdateToggleUI('chatLiveEnabled');
  lcUpdateToggleUI('chatCommunityEnabled');
  lcUpdateNavVisibility();
  if (typeof showToast === 'function') showToast('Chat settings saved <i class="fa-solid fa-check"></i>', 'success');
}

function lcUpdateToggleUI(checkboxId) {
  const cb = document.getElementById(checkboxId);
  if (!cb) return;
  const pill = cb.nextElementSibling;
  if (!pill) return;
  const knob = pill.querySelector('.toggle-knob');
  if (knob) knob.style.left = cb.checked ? '23px' : '3px';
  pill.style.background = cb.checked ? 'var(--primary,#7c3aed)' : 'var(--border,#cbd5e1)';
}


// ── Role helper ──
function lcIsPlatAdmin() { return typeof currentUser !== 'undefined' && currentUser && currentUser.role === 'platform_admin'; }
function lcGetSchoolIdFromCurrentUser() {
  if (typeof currentUser !== 'undefined' && currentUser && currentUser.id) return 'school_' + currentUser.id;
  if (typeof currentUser !== 'undefined' && currentUser && currentUser.username) return 'school_' + currentUser.username;
  try {
    const saved = JSON.parse(localStorage.getItem('ei_saved_login') || 'null');
    if (saved?.username) return 'school_' + saved.username;
  } catch {}
  return 'school_default';
}

function lcUpdateNavVisibility() {
  const cfg = lcGetSettings();
  const link = document.getElementById('livechatNavLink');
  if (!link) return;
  const shouldShow = cfg.liveEnabled || cfg.communityEnabled;
  link.style.display = shouldShow ? '' : 'none';
}

// Get current user info
function lcCurrentUser() {
  if (lcIsPlatAdmin()) return { role: 'platform', name: 'Platform Admin', id: '__platform__' };
  const name = (typeof currentUser !== 'undefined' && currentUser?.name) || document.getElementById('tbUser')?.textContent || 'School';
  const id = lcGetSchoolIdFromCurrentUser();
  return { role: 'school', name, id };
}

function lcGetCurrentSchoolId() { return lcGetSchoolIdFromCurrentUser(); }

function lcGetSchoolName(schoolId) {
  try {
    const schools = JSON.parse(localStorage.getItem('ei_platform_schools') || '[]');
    const found = schools.find(s => s.id === schoolId || ('school_'+s.username) === schoolId);
    if (found) return found.name || found.username || schoolId;
  } catch {}
  return schoolId.replace('school_', '');
}

// Message storage
function lcGetMsgs(schoolId) { try { return JSON.parse(localStorage.getItem(LC_MSG_KEY(schoolId)) || '[]'); } catch { return []; } }
function lcSaveMsgs(schoolId, msgs) { localStorage.setItem(LC_MSG_KEY(schoolId), JSON.stringify(msgs.slice(-500))); }
function lcGetCommunity() { try { return JSON.parse(localStorage.getItem(LC_COMMUNITY_KEY) || '[]'); } catch { return []; } }
function lcSaveCommunity(msgs) { localStorage.setItem(LC_COMMUNITY_KEY, JSON.stringify(msgs.slice(-1000))); }

function lcAddMsg(schoolId, role, text) {
  const msgs = lcGetMsgs(schoolId);
  msgs.push({ role, text, ts: Date.now() });
  lcSaveMsgs(schoolId, msgs);
  // Mark unread for the other side
  const unreadKey = LC_UNREAD_KEY(schoolId + '_' + (role === 'admin' ? 'school' : 'admin'));
  const cnt = parseInt(localStorage.getItem(unreadKey) || '0') + 1;
  localStorage.setItem(unreadKey, String(cnt));
}

function lcClearUnread(schoolId, side) {
  localStorage.removeItem(LC_UNREAD_KEY(schoolId + '_' + side));
}

function lcGetUnread(schoolId, side) {
  return parseInt(localStorage.getItem(LC_UNREAD_KEY(schoolId + '_' + side)) || '0');
}

function lcFormatTime(ts) {
  const d = new Date(ts);
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

// ── INIT LIVE CHAT SECTION ──
function initLiveChatSection() {
  const cfg = lcGetSettings();
  lcSwitchTab(_lcTab);
  lcUpdateNavVisibility();
  if (lcIsPlatAdmin()) {
    lcRenderAdminView(cfg);
  } else {
    lcRenderSchoolView(cfg);
  }
  lcStartPolling();
}

function lcSwitchTab(tab) {
  _lcTab = tab;
  document.querySelectorAll('.lct-tab').forEach(b => {
    b.classList.toggle('btn-primary', b.id === 'lct-' + tab);
    b.classList.toggle('btn-outline', b.id !== 'lct-' + tab);
  });
  document.getElementById('lcPanel-support').style.display = tab === 'support' ? '' : 'none';
  document.getElementById('lcPanel-community').style.display = tab === 'community' ? '' : 'none';
  if (tab === 'community') lcRenderCommunityPanel();
}

// ── ADMIN VIEW ──
function lcRenderAdminView(cfg) {
  cfg = cfg || lcGetSettings();
  const show = document.getElementById('lcAdminView');
  const dis  = document.getElementById('lcSupportDisabled');
  if (!cfg.liveEnabled) { if (show) show.style.display='none'; if (dis) dis.style.display=''; return; }
  if (show) show.style.display = '';
  if (dis) dis.style.display = 'none';
  lcRenderSchoolList();
}

function lcRenderSchoolList() {
  const list = document.getElementById('lcSchoolList');
  if (!list) return;
  let schools = [];
  try { schools = JSON.parse(localStorage.getItem('ei_platform_schools') || '[]'); } catch {}

  // Also collect schools from any existing message threads
  const extraIds = Object.keys(localStorage)
    .filter(k => k.startsWith('ei_chat_msgs_'))
    .map(k => k.replace('ei_chat_msgs_', ''))
    .filter(id => !schools.find(s => s.id === id || ('school_'+s.username) === id));

  const allIds = [
    ...schools.map(s => ({ id: s.id || ('school_'+s.username), name: s.name || s.username })),
    ...extraIds.map(id => ({ id, name: lcGetSchoolName(id) }))
  ];

  if (!allIds.length) {
    list.innerHTML = '<div style="padding:1.5rem;text-align:center;color:var(--muted);font-size:.82rem">No schools yet</div>';
    return;
  }

  list.innerHTML = allIds.map(({ id, name }) => {
    const msgs = lcGetMsgs(id);
    const last = msgs[msgs.length - 1];
    const unread = lcGetUnread(id, 'admin');
    const preview = last ? last.text.slice(0, 35) + (last.text.length > 35 ? '…' : '') : 'No messages yet';
    const initials = name.slice(0,2).toUpperCase();
    return `<div class="lc-school-item ${_lcActiveSchool===id?'active':''}" onclick="lcSelectSchool('${id}','${name.replace(/'/g,"\\'")}')">
      <div class="lc-school-avatar">${initials}</div>
      <div class="lc-school-info">
        <div class="lc-school-name">${name}</div>
        <div class="lc-school-preview">${preview}</div>
      </div>
      ${unread ? `<div class="lc-unread-dot"></div>` : ''}
    </div>`;
  }).join('');
}

function lcSelectSchool(schoolId, schoolName) {
  _lcActiveSchool = schoolId;
  lcClearUnread(schoolId, 'admin');
  lcRenderSchoolList();

  const header = document.getElementById('lcAdminChatHeader');
  if (header) header.innerHTML = '<i class="fa-solid fa-school"></i> ' + schoolName;

  const inputWrap = document.getElementById('lcAdminInput');
  if (inputWrap) inputWrap.style.display = 'flex';

  lcRenderAdminMessages(schoolId);
}

function lcRenderAdminMessages(schoolId) {
  const container = document.getElementById('lcAdminMessages');
  if (!container) return;
  const msgs = lcGetMsgs(schoolId || _lcActiveSchool);
  if (!msgs.length) {
    container.innerHTML = '<div style="text-align:center;color:var(--muted);font-size:.83rem;margin:auto">No messages yet. Say hello! </div>';
    return;
  }
  container.innerHTML = msgs.map(m => `
    <div style="display:flex;flex-direction:column;align-items:${m.role==='admin'?'flex-end':'flex-start'}">
      <div class="lc-bubble ${m.role==='admin'?'lc-me':'lc-admin'}">${lcEscape(m.text)}</div>
      <div class="lc-ts">${lcFormatTime(m.ts)}</div>
    </div>`).join('');
  container.scrollTop = container.scrollHeight;
}

function lcAdminSend() {
  const inp = document.getElementById('lcAdminMsgInput');
  if (!inp || !inp.value.trim() || !_lcActiveSchool) return;
  lcAddMsg(_lcActiveSchool, 'admin', inp.value.trim());
  inp.value = '';
  lcRenderAdminMessages(_lcActiveSchool);
  lcRenderSchoolList();
}

// ── SCHOOL VIEW ──
function lcRenderSchoolView(cfg) {
  cfg = cfg || lcGetSettings();
  const adminView = document.getElementById('lcAdminView');
  if (adminView) adminView.style.display = 'none';
  const show = document.getElementById('lcSchoolView');
  const dis  = document.getElementById('lcSupportDisabled');
  const widget = document.getElementById('fchatWidget');

  if (!cfg.liveEnabled) {
    if (show) show.style.display = 'none';
    if (dis) dis.style.display = '';
    if (widget) widget.style.display = 'none';
    return;
  }
  if (show) show.style.display = '';
  if (dis) dis.style.display = 'none';
  if (widget) widget.style.display = '';

  const schoolId = lcGetCurrentSchoolId();
  lcRenderSchoolMessages(schoolId, 'lcSchoolMessages');
}

function lcRenderSchoolMessages(schoolId, containerId) {
  const container = document.getElementById(containerId);
  if (!container) return;
  const msgs = lcGetMsgs(schoolId);
  const base = '<div class="lc-bubble lc-admin" style="max-width:75%;font-size:.83rem"> Hello! How can we help you today?</div>';
  if (!msgs.length) { container.innerHTML = base; return; }
  container.innerHTML = base + msgs.map(m => `
    <div style="display:flex;flex-direction:column;align-items:${m.role==='school'?'flex-end':'flex-start'}">
      <div class="lc-bubble ${m.role==='school'?'lc-me':'lc-admin'}" style="font-size:.83rem">${lcEscape(m.text)}</div>
      <div class="lc-ts">${lcFormatTime(m.ts)}</div>
    </div>`).join('');
  container.scrollTop = container.scrollHeight;
}

function lcSchoolSend() {
  const inp = document.getElementById('lcSchoolMsgInput');
  if (!inp || !inp.value.trim()) return;
  const schoolId = lcGetCurrentSchoolId();
  lcAddMsg(schoolId, 'school', inp.value.trim());
  inp.value = '';
  lcRenderSchoolMessages(schoolId, 'lcSchoolMessages');
}

// ── FLOATING CHAT WIDGET ──
function fchatToggle() {
  _fchatOpen = !_fchatOpen;
  const win = document.getElementById('fchatWindow');
  if (win) win.style.display = _fchatOpen ? 'flex' : 'none';
  if (_fchatOpen) {
    const schoolId = lcGetCurrentSchoolId();
    lcClearUnread(schoolId, 'school');
    lcRenderSchoolMessages(schoolId, 'fchatMessages');
    lcUpdateFchatBadge(schoolId);
  }
}

function fchatSend() {
  const inp = document.getElementById('fchatInput');
  if (!inp || !inp.value.trim()) return;
  const schoolId = lcGetCurrentSchoolId();
  lcAddMsg(schoolId, 'school', inp.value.trim());
  inp.value = '';
  lcRenderSchoolMessages(schoolId, 'fchatMessages');
}

function lcUpdateFchatBadge(schoolId) {
  const cnt = lcGetUnread(schoolId || lcGetCurrentSchoolId(), 'school');
  const badge = document.getElementById('fchatUnread');
  if (!badge) return;
  badge.textContent = cnt;
  badge.style.display = cnt > 0 ? 'flex' : 'none';
  // Nav badge
  const navBadge = document.getElementById('livechatBadge');
  if (navBadge) { navBadge.textContent = cnt; navBadge.style.display = cnt > 0 ? '' : 'none'; }
}

// ── COMMUNITY CHAT ──
function lcRenderCommunityPanel() {
  const cfg = lcGetSettings();
  const en = document.getElementById('lcCommunityEnabled');
  const dis = document.getElementById('lcCommunityDisabled');
  if (!cfg.communityEnabled) {
    if (en) en.style.display = 'none';
    if (dis) dis.style.display = '';
    return;
  }
  if (en) en.style.display = 'flex';
  if (dis) dis.style.display = 'none';

  const user = lcCurrentUser();
  const sender = document.getElementById('lcCommunitySender');
  if (sender) sender.textContent = user.name;

  lcRenderCommunityMessages();
}

function lcRenderCommunityMessages() {
  const container = document.getElementById('lcCommunityMessages');
  if (!container) return;
  const msgs = lcGetCommunity();
  const user = lcCurrentUser();
  if (!msgs.length) {
    container.innerHTML = '<div style="text-align:center;color:var(--muted);font-size:.83rem;margin:auto">Be the first to say something! </div>';
    return;
  }
  container.innerHTML = msgs.map(m => {
    const isMe = m.senderId === user.id;
    return `<div class="lc-community-wrap">
      <div class="lc-community-name ${isMe?'me':''}">${lcEscape(m.senderName)}${isMe?' (You)':''}</div>
      <div style="display:flex;flex-direction:column;align-items:${isMe?'flex-end':'flex-start'}">
        <div class="lc-bubble ${isMe?'lc-me':'lc-admin'}">${lcEscape(m.text)}</div>
        <div class="lc-ts">${lcFormatTime(m.ts)}</div>
      </div>
    </div>`;
  }).join('');
  container.scrollTop = container.scrollHeight;
}

function lcCommunitySend() {
  const inp = document.getElementById('lcCommunityInput');
  if (!inp || !inp.value.trim()) return;
  const user = lcCurrentUser();
  const msgs = lcGetCommunity();
  msgs.push({ senderId: user.id, senderName: user.name, text: inp.value.trim(), ts: Date.now() });
  lcSaveCommunity(msgs);
  inp.value = '';
  lcRenderCommunityMessages();
}

// ── POLLING (auto-refresh for new messages) ──
function lcStartPolling() {
  if (_lcPollTimer) clearInterval(_lcPollTimer);
  _lcPollTimer = setInterval(() => {
    const sec = document.getElementById('s-livechat');
    const secVisible = sec && sec.style.display !== 'none';
    if (lcIsPlatAdmin()) {
      if (secVisible && _lcActiveSchool) lcRenderAdminMessages(_lcActiveSchool);
      if (secVisible) lcRenderSchoolList();
    } else {
      const schoolId = lcGetCurrentSchoolId();
      if (secVisible) lcRenderSchoolMessages(schoolId, 'lcSchoolMessages');
      if (_fchatOpen) lcRenderSchoolMessages(schoolId, 'fchatMessages');
      lcUpdateFchatBadge(schoolId);
    }
    if (secVisible && _lcTab === 'community') lcRenderCommunityMessages();
  }, 3000);
}

function lcEscape(str) {
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

// ── Hook into go() navigation ──
document.addEventListener('DOMContentLoaded', function() {
  // Override go to catch livechat
  const _origGo = window.go;
  if (typeof _origGo === 'function') {
    window.go = function(sec, el) {
      _origGo(sec, el);
      if (sec === 'livechat') {
        setTimeout(initLiveChatSection, 50);
      }
    };
  }
  // Init floating contact
  initFloatingContact();
  lcUpdateNavVisibility();
  // Re-init after login settles
  setTimeout(lcInitAfterLogin, 1200);
});

function lcInitAfterLogin() {
  lcUpdateNavVisibility();
  const cfg = lcGetSettings();
  if (!lcIsPlatAdmin() && cfg.liveEnabled) {
    const widget = document.getElementById('fchatWidget');
    if (widget) widget.style.display = '';
  }
}

// ══════════════════════════════════════════════════════
// THEME COLOR ENGINE
// ══════════════════════════════════════════════════════
const THEME_KEY = 'ei_theme_v1';
const THEME_ENABLED_KEY = 'ei_theme_enabled'; // platform admin on/off

/* ── Shade generator: hex → 10-stop scale (50,100,...,900) ── */
function hexToRgb(hex) {
  const h = hex.replace('#','');
  return [parseInt(h.slice(0,2),16), parseInt(h.slice(2,4),16), parseInt(h.slice(4,6),16)];
}
function rgbToHex(r,g,b) {
  return '#'+[r,g,b].map(v=>Math.max(0,Math.min(255,Math.round(v))).toString(16).padStart(2,'0')).join('');
}
function generateShades(hex) {
  const [r,g,b] = hexToRgb(hex);
  const stops = [50,100,200,300,400,500,600,700,800,900];
  const shades = {};
  stops.forEach(stop => {
    let nr,ng,nb;
    if (stop <= 500) {
      const t = 1 - stop/500;
      nr = r + t*(255-r); ng = g + t*(255-g); nb = b + t*(255-b);
    } else {
      const t = (stop-500)/400;
      nr = r*(1-t*0.85); ng = g*(1-t*0.85); nb = b*(1-t*0.85);
    }
    shades[stop] = rgbToHex(nr,ng,nb);
  });
  return shades;
}

const THEME_PALETTES = {
  primary: [
    { name: 'Default', id: 'p-default',   base:'#7c3aed', dk:'#5b21b6', lt:'#ede9fe', btn:'#1a6fb5' },
    { name: 'Sky Blue',id: 'p-skyblue',   base:'#0284c7', dk:'#0369a1', lt:'#e0f2fe', btn:'#0284c7' },
    { name: 'Indigo',  id: 'p-indigo',    base:'#4f46e5', dk:'#4338ca', lt:'#e0e7ff', btn:'#4f46e5' },
    { name: 'Cobalt',  id: 'p-cobalt',    base:'#1d4ed8', dk:'#1e40af', lt:'#dbeafe', btn:'#1d4ed8' },
    { name: 'Pink',    id: 'p-pink',      base:'#db2777', dk:'#be185d', lt:'#fce7f3', btn:'#db2777' },
    { name: 'Slate',   id: 'p-slate',     base:'#475569', dk:'#334155', lt:'#f1f5f9', btn:'#475569' },
  ],
  green: [
    { name: 'Emerald', id: 'g-emerald',   base:'#10b981', dk:'#059669', lt:'#d1fae5' },
    { name: 'Forest',  id: 'g-forest',    base:'#16a34a', dk:'#15803d', lt:'#dcfce7' },
    { name: 'Lime',    id: 'g-lime',      base:'#65a30d', dk:'#4d7c0f', lt:'#ecfccb' },
    { name: 'Teal',    id: 'g-teal',      base:'#0d9488', dk:'#0f766e', lt:'#ccfbf1' },
    { name: 'Cyan',    id: 'g-cyan',      base:'#0891b2', dk:'#0e7490', lt:'#cffafe' },
    { name: 'Mint',    id: 'g-mint',      base:'#2dd4bf', dk:'#14b8a6', lt:'#f0fdfa' },
  ],
  red: [
    { name: 'Crimson', id: 'r-crimson',   base:'#dc2626', dk:'#b91c1c', lt:'#fee2e2' },
    { name: 'Rose',    id: 'r-rose',      base:'#e11d48', dk:'#be123c', lt:'#ffe4e6' },
    { name: 'Ruby',    id: 'r-ruby',      base:'#be123c', dk:'#9f1239', lt:'#fff1f2' },
    { name: 'Coral',   id: 'r-coral',     base:'#f43f5e', dk:'#e11d48', lt:'#fff1f2' },
    { name: 'Tomato',  id: 'r-tomato',    base:'#ef4444', dk:'#dc2626', lt:'#fef2f2' },
  ],
  yellow: [
    { name: 'Amber',   id: 'y-amber',     base:'#d97706', dk:'#b45309', lt:'#fef3c7' },
    { name: 'Gold',    id: 'y-gold',      base:'#ca8a04', dk:'#a16207', lt:'#fefce8' },
    { name: 'Lemon',   id: 'y-lemon',     base:'#eab308', dk:'#ca8a04', lt:'#fefce8' },
    { name: 'Orange',  id: 'y-orange',    base:'#ea580c', dk:'#c2410c', lt:'#ffedd5' },
    { name: 'Saffron', id: 'y-saffron',   base:'#f59e0b', dk:'#d97706', lt:'#fffbeb' },
  ],
  toggle: [
    { name: 'Purple',  id: 't-purple',    base:'#7c3aed', dk:'#5b21b6', lt:'#ede9fe' },
    { name: 'Green',   id: 't-green',     base:'#16a34a', dk:'#15803d', lt:'#dcfce7' },
    { name: 'Blue',    id: 't-blue',      base:'#2563eb', dk:'#1d4ed8', lt:'#dbeafe' },
    { name: 'Teal',    id: 't-teal',      base:'#0d9488', dk:'#0f766e', lt:'#ccfbf1' },
    { name: 'Pink',    id: 't-pink',      base:'#db2777', dk:'#be185d', lt:'#fce7f3' },
  ],
};

const THEME_DEFAULTS = { primary:'p-default', green:'g-forest', red:'r-crimson', yellow:'y-amber', toggle:'t-purple' };

function themeLoad() { try { return JSON.parse(localStorage.getItem(THEME_KEY)) || {}; } catch { return {}; } }
function themeSaveData(d) { localStorage.setItem(THEME_KEY, JSON.stringify(d)); }

function themeGetPalette(group, id) {
  return THEME_PALETTES[group].find(p => p.id === id);
}

function themeIsEnabled() {
  // Platform admin can disable theme customisation for schools
  try { return localStorage.getItem(THEME_ENABLED_KEY) !== '0'; } catch { return true; }
}

function themeApply(cfg) {
  cfg = cfg || themeLoad();

  // If platform has disabled theme customisation and current user is not platform admin, bail
  const isPlatAdmin = currentUser && (currentUser.role === 'platform_admin' || currentUser.role === 'superadmin');
  if (!themeIsEnabled() && !isPlatAdmin) {
    const style = document.getElementById('ei-theme-override');
    if (style) style.textContent = '';
    return;
  }

  let style = document.getElementById('ei-theme-override');
  if (!style) { style = document.createElement('style'); style.id = 'ei-theme-override'; document.head.appendChild(style); }

  const sel = {
    primary: cfg.primary || THEME_DEFAULTS.primary,
    green:   cfg.green   || THEME_DEFAULTS.green,
    red:     cfg.red     || THEME_DEFAULTS.red,
    yellow:  cfg.yellow  || THEME_DEFAULTS.yellow,
    toggle:  cfg.toggle  || THEME_DEFAULTS.toggle,
  };

  const p  = themeGetPalette('primary', sel.primary);
  const g  = themeGetPalette('green',   sel.green);
  const r  = themeGetPalette('red',     sel.red);
  const y  = themeGetPalette('yellow',  sel.yellow);
  const t  = themeGetPalette('toggle',  sel.toggle);

  const isDefault = sel.primary === 'p-default' && sel.green === 'g-forest' &&
                    sel.red === 'r-crimson' && sel.yellow === 'y-amber' && sel.toggle === 't-purple';

  if (isDefault) { style.textContent = ''; return; }

  // Generate full shade scales for each group
  const pS = generateShades(p.base);
  const gS = generateShades(g.base);
  const rS = generateShades(r.base);
  const yS = generateShades(y.base);
  const tS = generateShades(t.base);

  function shadeVars(prefix, shades) {
    return [50,100,200,300,400,500,600,700,800,900]
      .map(s => `      --${prefix}-${s}: ${shades[s]};`).join('\n');
  }

  style.textContent = `
    :root {
      --primary:      ${p.base};
      --primary-dk:   ${p.dk};
      --primary-lt:   ${p.lt};
      --secondary:    ${g.base};
      --secondary-dk: ${g.dk};
      --secondary-lt: ${g.lt};
      --teal:         ${g.base};
      --teal-lt:      ${g.lt};
      --cyan:         ${g.base};
      --cyan-lt:      ${g.lt};
      --success:      ${g.base};
      --danger:       ${r.base};
      --red:          ${r.base};
      --red-lt:       ${r.lt};
      --warning:      ${y.base};
      --amber:        ${y.base};
      --amber-lt:     ${y.lt};
      --orange:       ${y.base};
      --orange-lt:    ${y.lt};
      --toggle:       ${t.base};
      --toggle-dk:    ${t.dk};
      --toggle-lt:    ${t.lt};
      /* Primary shades */
${shadeVars('primary', pS)}
      /* Green/Secondary shades */
${shadeVars('green', gS)}
${shadeVars('secondary', gS)}
      /* Red/Danger shades */
${shadeVars('red', rS)}
${shadeVars('danger', rS)}
      /* Yellow/Amber shades */
${shadeVars('yellow', yS)}
${shadeVars('amber', yS)}
      /* Toggle shades */
${shadeVars('toggle', tS)}
    }
    .btn-primary { background: ${p.btn || p.base} !important; }
    .btn-primary:hover { background: ${p.dk} !important; }
    input[type=checkbox]:checked + .toggle-pill { background: ${t.base} !important; }
    .toggle-pill.on { background: ${t.base} !important; }
    .lang-btn.active { background: ${p.base}; box-shadow: 0 1px 4px ${p.base}55; }
    .tb.active { color: ${p.base}; border-bottom-color: ${p.base}; background: ${p.lt}; }
    .sn.active { background: ${p.btn || p.base} !important; }
    .fc-call { background: ${p.base} !important; }
  `;
}

function themeRenderSwatches() {
  const cfg = themeLoad();
  const enabled = themeIsEnabled();
  const sel = {
    primary: cfg.primary || THEME_DEFAULTS.primary,
    green:   cfg.green   || THEME_DEFAULTS.green,
    red:     cfg.red     || THEME_DEFAULTS.red,
    yellow:  cfg.yellow  || THEME_DEFAULTS.yellow,
    toggle:  cfg.toggle  || THEME_DEFAULTS.toggle,
  };

  // Update platform enable toggle UI
  const enableToggle = document.getElementById('themeEnabledToggle');
  if (enableToggle) enableToggle.checked = enabled;
  const enableStatus = document.getElementById('themeEnabledStatus');
  if (enableStatus) {
    enableStatus.innerHTML = enabled ? '<i class="fa-solid fa-circle-check"></i> Theme customisation is ON for all schools' : '<i class="fa-solid fa-lock"></i> Theme customisation is OFF (locked to current theme)';
    enableStatus.style.color = enabled ? '#16a34a' : '#dc2626';
  }

  function renderShadeStrip(palette) {
    const shades = generateShades(palette.base);
    return [50,100,200,300,400,500,600,700,800,900].map(s =>
      `<div title="${palette.name} ${s}" style="width:20px;height:20px;background:${shades[s]};border-radius:3px;flex-shrink:0"></div>`
    ).join('');
  }

  function render(containerId, group, cfgKey) {
    const el = document.getElementById(containerId);
    if (!el) return;
    el.innerHTML = THEME_PALETTES[group].map(p => {
      const isActive = sel[cfgKey] === p.id;
      return `<div style="display:flex;flex-direction:column;align-items:center;gap:.35rem;cursor:pointer;padding:.4rem .3rem;border-radius:8px;border:2px solid ${isActive?'var(--text)':'transparent'};transition:border-color .15s" onclick="themePickColor('${cfgKey}','${p.id}')" title="${p.name}">
        <div style="display:flex;gap:2px">${renderShadeStrip(p)}</div>
        <div style="font-size:.62rem;color:var(--muted);font-weight:${isActive?'700':'500'};text-align:center;max-width:200px">${p.name}</div>
      </div>`;
    }).join('');
  }

  render('tg-primary', 'primary', 'primary');
  render('tg-green',   'green',   'green');
  render('tg-red',     'red',     'red');
  render('tg-yellow',  'yellow',  'yellow');
  render('tg-toggle',  'toggle',  'toggle');
}

function themeToggleEnabled(val) {
  localStorage.setItem(THEME_ENABLED_KEY, val ? '1' : '0');
  themeRenderSwatches();
  if (!val) themeApply({});  // clear overrides for non-platform users instantly
  const st = document.getElementById('themeStatus');
  if (st) { st.innerHTML = val ? '<i class="fa-solid fa-circle-check"></i> Enabled for all schools' : '<i class="fa-solid fa-lock"></i> Disabled for schools'; st.style.color = val ? '#16a34a' : '#dc2626'; setTimeout(()=>{ st.innerHTML=''; },2500); }
}

function themePickColor(cfgKey, paletteId) {
  const cfg = themeLoad();
  cfg[cfgKey] = paletteId;
  themeSaveData(cfg);
  themeApply(cfg);
  themeRenderSwatches();
}

function themeSave() {
  const st = document.getElementById('themeStatus');
  if (st) { st.innerHTML = '<i class="fa-solid fa-circle-check"></i> Theme saved!'; st.style.color = '#16a34a'; setTimeout(()=>{ st.textContent=''; },2500); }
  if (typeof showToast === 'function') showToast('Theme saved <i class="fa-solid fa-check"></i>','success');
}

function themeReset() {
  localStorage.removeItem(THEME_KEY);
  themeApply({});
  themeRenderSwatches();
  const st = document.getElementById('themeStatus');
  if (st) { st.textContent = '↺ Reset to default'; st.style.color = 'var(--muted)'; setTimeout(()=>{ st.textContent=''; },2000); }
}

// Boot: apply saved theme on load
(function() {
  const saved = themeLoad();
  if (Object.keys(saved).length) themeApply(saved);
  document.addEventListener('DOMContentLoaded', function() {
    themeApply(themeLoad());
    themeRenderSwatches();
  });
})();

// ═══════════════════════════════════════════════════════════════════
//  ROLE-BASED ACCESS CONTROL — Platform Admin
//  Stores per-role permission maps, applies them at login time.
//  Keys:
//    ei_rbac_global          → { teacher:{...}, student:{...}, guest:{...} }
//    ei_rbac_<schoolId>      → same shape, overrides global for that school
// ═══════════════════════════════════════════════════════════════════

const K_RBAC_GLOBAL = 'ei_rbac_global';
const K_RBAC_SCHOOL = (id) => 'ei_rbac_' + id;

// ── Schema: every permission the UI exposes ──
const RBAC_SCHEMA = {
  teacher: {
    label: 'Teacher',
    icon: 'fa-chalkboard-user',
    color: '#1a6fb5',
    sections: [
      { key: 'dashboard',    label: 'Dashboard',           icon: 'fa-house',           defaultOn: true },
      { key: 'exambuilder',  label: 'Exam Builder',        icon: 'fa-pen-to-square',   defaultOn: true },
      {
        key: 'exams', label: 'Exams', icon: 'fa-file-pen', defaultOn: true,
        tabs: [
          { key: 'tabExamList',         label: 'Exam List',          defaultOn: true  },
          { key: 'tabExamTimetable',    label: 'Exam Timetable',     defaultOn: true  },
          { key: 'tabCreateExam',       label: 'Create Exam',        defaultOn: false },
          { key: 'tabUploadMarks',      label: 'Upload Marks',       defaultOn: true  },
          { key: 'tabAnalyse',          label: 'Analyse Results',    defaultOn: false },
          { key: 'tabMeritList',        label: 'Merit List',         defaultOn: false },
          { key: 'tabSummaryAnalytics', label: 'Summary Analytics',  defaultOn: false },
        ]
      },
      { key: 'papers',       label: 'Papers & Resources',  icon: 'fa-folder-open',     defaultOn: true,
        tabs: [
          { key: 'tabTermlyExams', label: 'Termly Exams', defaultOn: true  },
          { key: 'tabRevision',    label: 'Revision',     defaultOn: true  },
        ]
      },
      {
        key: 'fees', label: 'Fees (Class Teachers)', icon: 'fa-coins', defaultOn: true,
        tabs: [
          { key: 'tabFeeOverview',   label: 'Overview',         defaultOn: true  },
          { key: 'tabFeeStructure',  label: 'Fee Structure',    defaultOn: false },
          { key: 'tabFeePayments',   label: 'Record Payment',   defaultOn: true  },
          { key: 'tabFeeStudents',   label: 'Student Balances', defaultOn: true  },
          { key: 'tabFeeImport',     label: 'Import Fees',      defaultOn: false },
          { key: 'tabFeeReminders',  label: 'Reminders',        defaultOn: true  },
          { key: 'tabFeeReceipts',   label: 'Receipts',         defaultOn: true  },
        ]
      },
      {
        key: 'staffdetails', label: 'Staff Details', icon: 'fa-id-card', defaultOn: false,
        tabs: [
          { key: 'sdpList',    label: 'Directory',   defaultOn: true  },
          { key: 'sdpAddEdit', label: 'Add / Edit',  defaultOn: false },
          { key: 'sdpLeave',   label: 'Leave',       defaultOn: false },
          { key: 'sdpDocs',    label: 'Documents',   defaultOn: false },
          { key: 'sdpRoles',   label: 'Roles',       defaultOn: false },
          { key: 'sdpSalary',  label: 'Salary',      defaultOn: false },
        ]
      },
      {
        key: 'salaries', label: 'Finance → Salaries', icon: 'fa-money-bill-wave', defaultOn: false,
        tabs: [
          { key: 'tabStaffSalary', label: 'Staff Salary', defaultOn: false },
          { key: 'tabPayroll',     label: 'Payroll',      defaultOn: false },
          { key: 'tabPayslips',    label: 'Payslips',     defaultOn: false },
        ]
      },
      { key: 'messaging',    label: 'Messaging',            icon: 'fa-comments',        defaultOn: false },
      { key: 'settings',     label: 'Settings',             icon: 'fa-sliders',         defaultOn: true  },
    ],
    extras: [
      { key: 'canAnalyse',  label: 'Can run Analysis (override per-teacher)',  defaultOn: false },
      { key: 'canReport',   label: 'Can generate Report Forms',               defaultOn: false },
      { key: 'canMerit',    label: 'Can view Merit List',                     defaultOn: false },
    ]
  },
  student: {
    label: 'Student',
    icon: 'fa-user-graduate',
    color: '#059669',
    sections: [
      { key: 'spResults', label: 'Results / Report Cards', icon: 'fa-chart-bar',      defaultOn: true  },
      { key: 'spFees',    label: 'Fee Balance & Receipts', icon: 'fa-coins',           defaultOn: true  },
      { key: 'spPapers',  label: 'Papers & Resources',     icon: 'fa-folder-open',     defaultOn: true  },
    ],
    extras: []
  },
  guest: {
    label: 'Guest',
    icon: 'fa-user',
    color: '#7c3aed',
    sections: [
      { key: 'exambuilder',    label: 'Exam Builder (view/create)',  icon: 'fa-pen-to-square', defaultOn: true  },
      { key: 'guestPapers',    label: 'Papers & Resources',          icon: 'fa-folder-open',   defaultOn: true  },
      { key: 'guestDownload',  label: 'Download / Print Exams',      icon: 'fa-download',      defaultOn: false },
    ],
    extras: []
  }
};

// ── Build a default permissions object for a role ──
function rbacDefaults(role) {
  const schema = RBAC_SCHEMA[role];
  if (!schema) return {};
  const cfg = {};
  schema.sections.forEach(sec => {
    cfg[sec.key] = sec.defaultOn;
    (sec.tabs || []).forEach(tab => { cfg[sec.key + '__' + tab.key] = tab.defaultOn; });
  });
  (schema.extras || []).forEach(ex => { cfg[ex.key] = ex.defaultOn; });
  return cfg;
}

// ── Load / save helpers ──
function rbacLoad(schoolId) {
  const key = schoolId ? K_RBAC_SCHOOL(schoolId) : K_RBAC_GLOBAL;
  try { return JSON.parse(localStorage.getItem(key)) || {}; } catch { return {}; }
}
function rbacSaveRaw(cfg, schoolId) {
  const key = schoolId ? K_RBAC_SCHOOL(schoolId) : K_RBAC_GLOBAL;
  localStorage.setItem(key, JSON.stringify(cfg));
}
function rbacHasSchoolOverride(schoolId) {
  if (!schoolId) return false;
  return localStorage.getItem(K_RBAC_SCHOOL(schoolId)) !== null;
}
// Effective config for a role in a school context
function rbacEffective(role, schoolId) {
  const globalCfg  = rbacLoad(null)[role]  || rbacDefaults(role);
  if (!schoolId) return globalCfg;
  const schoolFull = rbacLoad(schoolId);
  const schoolRole = schoolFull[role];
  return (schoolRole && Object.keys(schoolRole).length) ? schoolRole : globalCfg;
}

// ── UI state ──
let _rbacMode = 'global';
let _rbacRole = 'teacher';

function rbacSwitchMode(mode) {
  _rbacMode = mode;
  const btnG = document.getElementById('rbacModeGlobal');
  const btnS = document.getElementById('rbacModeSchool');
  const picker = document.getElementById('rbacSchoolPicker');
  if (btnG) btnG.className = mode === 'global' ? 'btn btn-primary btn-sm' : 'btn btn-outline btn-sm';
  if (btnS) btnS.className = mode === 'school' ? 'btn btn-primary btn-sm' : 'btn btn-outline btn-sm';
  if (picker) picker.style.display = mode === 'school' ? '' : 'none';
  if (mode === 'school') {
    const sel = document.getElementById('rbacSchoolSelect');
    if (sel) {
      loadPlatform();
      sel.innerHTML = '<option value="">— Select a school —</option>' +
        platformSchools.map(s => `<option value="${s.id}">${s.name}</option>`).join('');
    }
  }
  rbacRender();
}

function rbacSelectRole(role, btn) {
  _rbacRole = role;
  document.querySelectorAll('#rbacRoleTabBar button').forEach(b => {
    b.style.borderBottomColor = 'transparent';
    b.style.color = 'var(--text)';
    b.style.fontWeight = '500';
  });
  if (btn) {
    btn.style.borderBottomColor = 'var(--primary, #4f7cff)';
    btn.style.color = 'var(--primary, #4f7cff)';
    btn.style.fontWeight = '700';
  }
  rbacRender();
}

function _rbacCurrentSchoolId() {
  if (_rbacMode !== 'school') return null;
  const sel = document.getElementById('rbacSchoolSelect');
  return (sel && sel.value) ? sel.value : null;
}

function rbacRender() {
  const root = document.getElementById('rbacPermissionsRoot');
  if (!root) return;

  const schoolId = _rbacCurrentSchoolId();
  const role = _rbacRole;
  const schema = RBAC_SCHEMA[role];
  if (!schema) { root.innerHTML = ''; return; }

  // School override note
  const note = document.getElementById('rbacSchoolNote');
  if (note) note.style.display = (schoolId && rbacHasSchoolOverride(schoolId)) ? '' : 'none';
  const clearBtn = document.getElementById('rbacClearSchoolBtn');
  if (clearBtn) clearBtn.style.display = (schoolId && rbacHasSchoolOverride(schoolId)) ? '' : 'none';

  // If school mode but none selected
  if (_rbacMode === 'school' && !schoolId) {
    root.innerHTML = '<p style="color:var(--muted);font-size:.84rem;padding:.5rem 0">Select a school above to configure its role permissions.</p>';
    return;
  }

  // Get effective config (school override → global fallback)
  const globalCfg = rbacLoad(null)[role]  || rbacDefaults(role);
  const schoolFull = schoolId ? rbacLoad(schoolId) : null;
  const schoolRole = schoolFull ? schoolFull[role] : null;
  const effectiveCfg = (schoolRole && Object.keys(schoolRole).length) ? schoolRole : globalCfg;

  // Override note for school mode
  if (schoolId && !(schoolRole && Object.keys(schoolRole).length)) {
    root.innerHTML = '<div style="font-size:.78rem;color:#64748b;background:var(--bg);border:1px dashed var(--border);border-radius:8px;padding:.5rem .75rem;margin-bottom:.75rem">ℹ️ No school-specific overrides set — showing global defaults. Saving will create a school override.</div>';
  } else {
    root.innerHTML = '';
  }

  const roleColor = schema.color;

  // Build sections
  let html = `<div style="display:flex;flex-direction:column;gap:.65rem">`;

  schema.sections.forEach(sec => {
    const secOn = effectiveCfg[sec.key] !== false;
    const hasTabs = sec.tabs && sec.tabs.length;

    html += `<div style="border:1.5px solid var(--border);border-radius:10px;overflow:hidden">
      <div style="display:flex;align-items:center;justify-content:space-between;padding:.6rem 1rem;background:var(--surface)">
        <span style="font-weight:700;font-size:.87rem;display:flex;align-items:center;gap:.5rem">
          <i class="fa-solid ${sec.icon}" style="color:${roleColor};width:16px;text-align:center"></i>
          ${sec.label}
        </span>
        <label class="plat-nav-toggle">
          <input type="checkbox" id="rbac_sec_${role}_${sec.key}" ${secOn ? 'checked' : ''}
            onchange="(function(cb){
              var tl=document.getElementById('rbacTabs_${role}_${sec.key}');
              if(tl) tl.style.display=cb.checked?'':'none';
            })(this)"/>
          <span class="plat-nav-slider"></span>
        </label>
      </div>`;

    if (hasTabs) {
      html += `<div id="rbacTabs_${role}_${sec.key}" style="${secOn ? '' : 'display:none'}">`;
      sec.tabs.forEach((tab, i) => {
        const tabOn = effectiveCfg[sec.key + '__' + tab.key] !== false;
        const border = i < sec.tabs.length ? 'border-top:1px solid var(--border-lt,#f1f5f9)' : '';
        html += `<div style="display:flex;align-items:center;justify-content:space-between;padding:.38rem 1rem .38rem 2.2rem;${border};background:var(--bg)">
          <span style="font-size:.81rem;color:var(--muted)">${tab.label}</span>
          <label class="plat-nav-toggle sm">
            <input type="checkbox" id="rbac_tab_${role}_${sec.key}__${tab.key}" ${tabOn ? 'checked' : ''}/>
            <span class="plat-nav-slider"></span>
          </label>
        </div>`;
      });
      html += `</div>`;
    }
    html += `</div>`;
  });

  // Extra capabilities
  if (schema.extras && schema.extras.length) {
    html += `<div style="border:1.5px solid var(--border);border-radius:10px;overflow:hidden">
      <div style="padding:.6rem 1rem;background:var(--surface);font-weight:700;font-size:.87rem;display:flex;align-items:center;gap:.5rem">
        <i class="fa-solid fa-star" style="color:${roleColor};width:16px;text-align:center"></i>
        Extra Capabilities
      </div>`;
    schema.extras.forEach((ex, i) => {
      const exOn = effectiveCfg[ex.key] !== false && effectiveCfg[ex.key] !== undefined
        ? effectiveCfg[ex.key]
        : ex.defaultOn;
      const border = i > 0 ? 'border-top:1px solid var(--border-lt,#f1f5f9)' : '';
      html += `<div style="display:flex;align-items:center;justify-content:space-between;padding:.42rem 1rem .42rem 2.2rem;${border};background:var(--bg)">
        <span style="font-size:.81rem;color:var(--muted)">${ex.label}</span>
        <label class="plat-nav-toggle sm">
          <input type="checkbox" id="rbac_extra_${role}_${ex.key}" ${exOn ? 'checked' : ''}/>
          <span class="plat-nav-slider"></span>
        </label>
      </div>`;
    });
    html += `</div>`;
  }

  html += `</div>`;

  // Append to existing content
  const existingContent = root.innerHTML;
  root.innerHTML = existingContent + html;
}

function rbacCollectCurrent() {
  const role = _rbacRole;
  const schema = RBAC_SCHEMA[role];
  if (!schema) return {};
  const cfg = {};
  schema.sections.forEach(sec => {
    const secCb = document.getElementById(`rbac_sec_${role}_${sec.key}`);
    if (secCb) cfg[sec.key] = secCb.checked;
    (sec.tabs || []).forEach(tab => {
      const tabCb = document.getElementById(`rbac_tab_${role}_${sec.key}__${tab.key}`);
      if (tabCb) cfg[sec.key + '__' + tab.key] = tabCb.checked;
    });
  });
  (schema.extras || []).forEach(ex => {
    const exCb = document.getElementById(`rbac_extra_${role}_${ex.key}`);
    if (exCb) cfg[ex.key] = exCb.checked;
  });
  return cfg;
}

function rbacSave() {
  const role = _rbacRole;
  const schoolId = _rbacCurrentSchoolId();
  const collected = rbacCollectCurrent();

  // Load the full config object and update just this role
  const full = rbacLoad(schoolId);
  full[role] = collected;
  rbacSaveRaw(full, schoolId);

  const note = document.getElementById('rbacSchoolNote');
  if (note) note.style.display = (schoolId && rbacHasSchoolOverride(schoolId)) ? '' : 'none';
  const clearBtn = document.getElementById('rbacClearSchoolBtn');
  if (clearBtn) clearBtn.style.display = (schoolId && rbacHasSchoolOverride(schoolId)) ? '' : 'none';

  const st = document.getElementById('rbacStatus');
  if (st) {
    st.innerHTML = `<i class="fa-solid fa-circle-check" style="color:#10b981"></i> ${schoolId ? 'Saved for this school.' : 'Saved globally — applies to all schools without a specific override.'}`;
    st.style.color = '#10b981';
    setTimeout(() => { if (st) st.innerHTML = ''; }, 4000);
  }
  showToast('<i class="fa-solid fa-circle-check"></i> Role permissions saved!', 'success');

  // Re-apply if we're inside a school right now
  if (currentUser && currentUser.role !== 'platform_admin') {
    applyRbacPermissions();
  }
}

function rbacReset() {
  const role = _rbacRole;
  const schoolId = _rbacCurrentSchoolId();
  const target = schoolId ? 'this school' : 'all schools (global)';
  if (!confirm(`Reset ${role} permissions to defaults for ${target}?`)) return;

  const full = rbacLoad(schoolId);
  full[role] = rbacDefaults(role);
  rbacSaveRaw(full, schoolId);
  rbacRender();

  showToast(`${RBAC_SCHEMA[role].label} permissions reset to defaults.`, 'info');
  const st = document.getElementById('rbacStatus');
  if (st) { st.textContent = '↺ Reset to defaults.'; setTimeout(() => { st.textContent = ''; }, 3000); }
}

function rbacClearSchoolOverride() {
  const schoolId = _rbacCurrentSchoolId();
  if (!schoolId) return;
  loadPlatform();
  const school = platformSchools.find(s => s.id === schoolId);
  const name = school ? school.name : 'this school';
  if (!confirm(`Remove all RBAC overrides for "${name}"?\n\nIt will revert to global settings.`)) return;
  localStorage.removeItem(K_RBAC_SCHOOL(schoolId));
  rbacRender();
  showToast('School RBAC override removed — using global settings.', 'info');
}

// ════════════════════════════════════════════════════
//  APPLY RBAC PERMISSIONS AT RUNTIME
//  Called after login, uses effective config for school
// ════════════════════════════════════════════════════

function applyRbacPermissions() {
  if (!currentUser) return;
  const role = currentUser.role;

  if (role === 'teacher') {
    applyRbacTeacher();
  } else if (role === 'student') {
    applyRbacStudent();
  } else if (role === 'guest') {
    applyRbacGuest();
  }
}

function applyRbacTeacher() {
  const cfg = rbacEffective('teacher', currentSchoolId);

  // Sections — hide/show nav links
  const teacherSections = ['dashboard','exambuilder','exams','papers','fees','staffdetails','messaging','settings'];
  teacherSections.forEach(sec => {
    const allowed = cfg[sec] !== false;
    document.querySelectorAll(`[data-s="${sec}"]`).forEach(el => {
      // Only restrict if already visible (don't fight platform nav config)
      if (!allowed) el.style.display = 'none';
    });
  });

  // Staff Details sub-tabs
  ['sdpList','sdpAddEdit','sdpLeave','sdpDocs','sdpRoles','sdpSalary'].forEach(tabId => {
    const key = 'staffdetails__' + tabId;
    const allowed = cfg[key] !== false;
    document.querySelectorAll(`[onclick*="${tabId}"]`).forEach(btn => {
      if (!allowed) btn.style.display = 'none';
    });
  });

  // Finance → Salaries main tab button
  if (cfg['salaries'] === false) {
    const salBtn = document.getElementById('fmtSalaries');
    if (salBtn) salBtn.style.display = 'none';
  }

  // Salaries sub-tabs (only relevant when salaries section is allowed)
  ['tabStaffSalary','tabPayroll','tabPayslips'].forEach(tabId => {
    const key = 'salaries__' + tabId;
    const allowed = cfg[key] !== false;
    document.querySelectorAll(`[onclick*="${tabId}"]`).forEach(btn => {
      if (!allowed) btn.style.display = 'none';
    });
  });

  // Exam sub-tabs
  const examTabs = ['tabExamList','tabExamTimetable','tabCreateExam','tabUploadMarks','tabAnalyse','tabMeritList','tabSummaryAnalytics'];
  examTabs.forEach(tabId => {
    const key = 'exams__' + tabId;
    const allowed = cfg[key] !== false;
    document.querySelectorAll(`[onclick*="${tabId}"]`).forEach(btn => {
      if (!allowed) btn.style.display = 'none';
    });
  });

  // Fees sub-tabs
  const feeTabs = ['tabFeeOverview','tabFeeStructure','tabFeePayments','tabFeeStudents','tabFeeImport','tabFeeReminders','tabFeeReceipts'];
  feeTabs.forEach(tabId => {
    const key = 'fees__' + tabId;
    const allowed = cfg[key] !== false;
    document.querySelectorAll(`[onclick*="${tabId}"]`).forEach(btn => {
      if (!allowed) btn.style.display = 'none';
    });
  });

  // Papers sub-tabs
  ['tabTermlyExams','tabRevision'].forEach(tabId => {
    const key = 'papers__' + tabId;
    const allowed = cfg[key] !== false;
    document.querySelectorAll(`[onclick*="${tabId}"]`).forEach(btn => {
      if (!allowed) btn.style.display = 'none';
    });
  });

  // Extras: override per-teacher canAnalyse, canReport, canMerit defaults
  // RBAC sets the DEFAULT; per-teacher flag can still elevate if admin set it
  if (cfg.canAnalyse === false && !currentUser.canAnalyse) {
    const btn = document.getElementById('tbAnalyse');
    if (btn) btn.style.display = 'none';
  }
  if (cfg.canMerit === false && !currentUser.canMerit) {
    const btn = document.getElementById('tbMeritList') || document.querySelector('[onclick*="tabMeritList"]');
    if (btn) btn.style.display = 'none';
  }
}

function applyRbacStudent() {
  const cfg = rbacEffective('student', currentSchoolId);

  // Student portal tabs
  const tabMap = { spResults: 'spResults', spFees: 'spFees', spPapers: 'spPapers' };
  Object.entries(tabMap).forEach(([cfgKey, tabId]) => {
    const allowed = cfg[cfgKey] !== false;
    const tabBtn = document.querySelector(`[onclick*="${tabId}"]`);
    const tabPanel = document.getElementById(tabId);
    if (!allowed) {
      if (tabBtn) tabBtn.style.display = 'none';
      if (tabPanel) tabPanel.style.display = 'none';
    }
  });
}

function applyRbacGuest() {
  const cfg = rbacEffective('guest', currentSchoolId);

  // Exam Builder tab
  if (cfg['exambuilder'] === false) {
    const btn = document.getElementById('guestTabBtnEB');
    const panel = document.getElementById('guestPanelEB');
    if (btn) btn.style.display = 'none';
    if (panel) panel.style.display = 'none';
  }

  // Papers tab
  if (cfg['guestPapers'] === false) {
    const btn = document.getElementById('guestTabBtnPapers');
    const panel = document.getElementById('guestPanelPapers');
    if (btn) btn.style.display = 'none';
    if (panel) panel.style.display = 'none';
  }

  // Download/print — controlled via existing platExamDlFee mechanism;
  // RBAC adds a second layer: if disabled, override the unlock check
  if (cfg['guestDownload'] === false) {
    // Store flag; the print/download buttons read window._rbacNoGuestDownload
    window._rbacNoGuestDownload = true;
  } else {
    window._rbacNoGuestDownload = false;
  }
}

// ─── Hook into existing finishLogin to run RBAC after platform nav config ───
(function() {
  const _origFinishLogin = typeof finishLogin === 'function' ? finishLogin : null;
  if (!_origFinishLogin) return;
  window._rbacHooked = true;
})();

// ─── Ensure RBAC is applied after login & nav config ───
// We patch applyPlatformNavConfig (which already runs post-login)
const _origApplyPlatformNavConfig = typeof applyPlatformNavConfig === 'function'
  ? applyPlatformNavConfig : null;

if (_origApplyPlatformNavConfig) {
  window.applyPlatformNavConfig = function() {
    _origApplyPlatformNavConfig();
    // Run RBAC after platform nav config so we can further restrict
    if (currentUser && currentUser.role !== 'platform_admin' &&
        currentUser.role !== 'superadmin' && currentUser.role !== 'admin' &&
        currentUser.role !== 'principal' && currentUser.role !== 'bursar') {
      applyRbacPermissions();
    }
  };
}

// ─── Also hook finishStudentPortal and finishGuestLogin ───
const _origFinishStudentPortal = typeof finishStudentPortal === 'function' ? finishStudentPortal : null;
if (_origFinishStudentPortal) {
  window.finishStudentPortal = function(school) {
    _origFinishStudentPortal(school);
    applyRbacStudent();
  };
}

const _origFinishGuestLogin = typeof finishGuestLogin === 'function' ? finishGuestLogin : null;
if (_origFinishGuestLogin) {
  window.finishGuestLogin = function(school) {
    _origFinishGuestLogin(school);
    applyRbacGuest();
  };
}

// ─── Initialize RBAC UI when Platform Admin opens the Access Control tab ───
// Patch openPlatTab to trigger rbacRender when the access tab is opened
const _origOpenPlatTab = typeof openPlatTab === 'function' ? openPlatTab : null;
if (_origOpenPlatTab) {
  window.openPlatTab = function(tabId, btn) {
    _origOpenPlatTab(tabId, btn);
    if (tabId === 'platTab-access') {
      // Init unlock school list
      if (typeof platLoadExamDlFee === 'function') platLoadExamDlFee();
      // Init RBAC
      setTimeout(() => {
        rbacSwitchMode('global');
        rbacSelectRole('teacher', document.getElementById('rbacRoleTab-teacher'));
      }, 0);
    }
    if (tabId === 'platTab-hrpayroll') {
      platInitHRPayroll();
    }
    if (tabId === 'platTab-reports') {
      platInitReports();
    }
  };
}

// ═══════════════════════════════════════════════════════════════
//  BUG DETECTOR & TROUBLESHOOTER — Platform Admin Module
//  Accessible via Platform Admin → Bug Detector tab
// ═══════════════════════════════════════════════════════════════

let _bdCurrentTab = 'checks';
let _bdLastResults = [];

function bugDetectorInit() {
  // Reset to idle state when tab opens
  const content = document.getElementById('bdContent');
  if (content && !_bdLastResults.length) {
    content.innerHTML = `
      <div style="text-align:center;padding:2.5rem 1rem;color:var(--muted)">
        <i class="fa-solid fa-bug" style="font-size:2.2rem;opacity:.25;margin-bottom:.75rem;display:block"></i>
        <div style="font-size:.85rem">Click <strong>Run Diagnostics</strong> to scan your platform for bugs, security issues and misconfigurations.</div>
      </div>`;
  }
}

function bdSwitchTab(tab, btn) {
  _bdCurrentTab = tab;
  document.querySelectorAll('#platTab-bugdetector [id^="bdSubTab-"]').forEach(b => {
    b.style.borderBottom = '3px solid transparent';
    b.style.color = 'var(--text)';
    b.style.fontWeight = '500';
  });
  if (btn) {
    btn.style.borderBottom = '3px solid var(--primary,#4f7cff)';
    btn.style.color = 'var(--primary,#4f7cff)';
    btn.style.fontWeight = '700';
  }
  if (_bdLastResults.length) bdRenderResults(_bdLastResults);
}

function bugDetectorRunAll() {
  const btn = document.getElementById('bdRunBtn');
  if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Scanning…'; }

  setTimeout(() => {
    const results = bdRunChecks();
    _bdLastResults = results;
    bdUpdateSummary(results);
    bdRenderResults(results);
    if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fa-solid fa-rotate-right"></i> Re-run'; }
    const fails = results.filter(r => r.sev === 'critical' || r.sev === 'high').length;
    showToast(fails ? `<i class="fa-solid fa-triangle-exclamation"></i> ${fails} critical/high issue${fails>1?'s':''} found` : '<i class="fa-solid fa-circle-check"></i> Diagnostics complete — no critical issues', fails ? 'error' : 'success');
  }, 600);
}

function bdRunChecks() {
  const checks = [];
  const ls = window.localStorage;

  // ── HELPER ──
  function chk(id, label, cat, sev, pass, note, fix) {
    checks.push({ id, label, cat, sev, pass, note, fix: fix || null });
  }

  // ── SECURITY CHECKS ──
  const creds = (() => { try { return JSON.parse(ls.getItem('ei_platform_creds')); } catch { return null; } })();
  const savedLogin = (() => { try { return JSON.parse(ls.getItem('ei_saved_login')); } catch { return null; } })();

  chk('pwd_rememberme', 'Remember Me does not persist plain-text password', 'security', 'high',
    !(savedLogin && savedLogin.password),
    savedLogin && savedLogin.password
      ? 'ei_saved_login contains the user\'s password in plain text. Anyone with localStorage access can read it.'
      : 'ei_saved_login contains only the username — password not persisted.',
    'Remove the password field from maybeSaveCreds() in doUnifiedLogin().');

  chk('pwd_platform', 'Platform admin password hashing', 'security', 'high',
    false, // Always warn — plain text by design in this architecture
    'Platform credentials stored as plain JSON in localStorage. Consider SHA-256 via Web Crypto API.',
    'Use crypto.subtle.digest("SHA-256", ...) before saving and comparing passwords.');

  const schools = (() => { try { return JSON.parse(ls.getItem('ei_platform_schools')) || []; } catch { return []; } })();
  const weakPassSchools = schools.filter(s => s.password && s.password.length < 6);
  chk('pwd_school_weak', 'No school accounts have passwords shorter than 6 characters', 'security', 'medium',
    weakPassSchools.length === 0,
    weakPassSchools.length ? `${weakPassSchools.length} school(s) with short passwords: ${weakPassSchools.map(s=>s.name).join(', ')}` : 'All school passwords meet minimum length.',
    'Enforce minimum 6-character passwords in platAddSchool() and addSchoolFromSettings().');

  chk('backdoor_superadmin', 'Hardcoded superadmin backdoor removed', 'security', 'critical',
    typeof doUnifiedLogin === 'function'
      ? !doUnifiedLogin.toString().includes("'superadmin'")
      : false,
    doUnifiedLogin && doUnifiedLogin.toString().includes("'superadmin'")
      ? 'Code still contains: if (u===\'superadmin\' && p===\'super123\'). Anyone who views the JS source gains full access.'
      : 'Backdoor not detected in source.',
    'Delete lines 756-764 in script.js — use enterSchoolAsPlatformAdmin() from the dashboard instead.');

  chk('xss_deactivation', 'School deactivation message HTML-escaped before injection', 'security', 'high',
    typeof doUnifiedLogin === 'function'
      ? doUnifiedLogin.toString().includes('escHtml(') || doUnifiedLogin.toString().includes('escapeHtml(')
      : false,
    'deactivationMessage is concatenated into err.innerHTML without escaping. XSS via admin-entered suspension message is possible.',
    'Add escHtml() helper and wrap msg: err.innerHTML = \'...\' + escHtml(msg);');

  chk('lockout_bruteforce', 'Login brute-force lockout active', 'security', 'medium',
    typeof checkLoginLock === 'function',
    typeof checkLoginLock === 'function'
      ? 'checkLoginLock() found — lockout is active.'
      : 'No attempt counter or lockout on login functions. Unlimited password guessing is possible.',
    'Add checkLoginLock() / recordFailedAttempt() helpers and call them at the top of doPlatformLogin().');

  // ── RBAC CHECKS ──
  chk('rbac_schema_present', 'RBAC_SCHEMA defined with all 3 roles', 'rbac', 'critical',
    typeof RBAC_SCHEMA !== 'undefined' && RBAC_SCHEMA.teacher && RBAC_SCHEMA.student && RBAC_SCHEMA.guest,
    typeof RBAC_SCHEMA !== 'undefined' ? 'RBAC_SCHEMA present with roles: ' + Object.keys(RBAC_SCHEMA).join(', ') : 'RBAC_SCHEMA is undefined!',
    'Check that the RBAC section at line 16258 of script.js was not accidentally deleted.');

  chk('rbac_defaults_fn', 'rbacDefaults() function available', 'rbac', 'critical',
    typeof rbacDefaults === 'function',
    typeof rbacDefaults === 'function' ? 'rbacDefaults() is defined.' : 'rbacDefaults() is missing — RBAC will not initialise.',
    'Ensure rbacDefaults() is present in script.js.');

  chk('rbac_effective_fn', 'rbacEffective() falls back to global when no school override', 'rbac', 'high',
    (() => { try { const r = rbacEffective('teacher', 'nonexistent_school_id_test'); return typeof r === 'object' && r !== null; } catch { return false; } })(),
    'rbacEffective() tested with unknown school ID — should return global defaults.',
    'Verify rbacEffective() returns globalCfg when schoolFull[role] is empty.');

  const globalRbac = (() => { try { return JSON.parse(ls.getItem('ei_rbac_global')) || {}; } catch { return {}; } })();
  chk('rbac_global_saved', 'Global RBAC config has been saved at least once', 'rbac', 'medium',
    Object.keys(globalRbac).length > 0,
    Object.keys(globalRbac).length > 0 ? 'Global RBAC config found for roles: ' + Object.keys(globalRbac).join(', ') : 'No global RBAC config saved yet. Default permissions apply to all schools.',
    'Open Platform Admin → Access Control and click "Save Role Permissions" for each role.');

  chk('rbac_plattab_access', 'platTab-access panel present in DOM', 'rbac', 'critical',
    !!document.getElementById('platTab-access'),
    document.getElementById('platTab-access') ? 'platTab-access panel found in DOM.' : 'platTab-access element missing from DOM — RBAC UI will not render.',
    'Ensure the <div id="platTab-access"> block is present in index.html.');

  chk('rbac_patch_fn', 'openPlatTab patched to init RBAC on Access Control tab', 'rbac', 'high',
    window.openPlatTab && window.openPlatTab.toString().includes('platTab-access'),
    window.openPlatTab && window.openPlatTab.toString().includes('platTab-access')
      ? 'openPlatTab is patched — RBAC initialises when Access Control tab is opened.'
      : 'openPlatTab patch missing or incomplete — RBAC may not initialise on tab open.',
    'Apply PATCH 3 from the Auto-Fix tab.');

  // ── STORAGE / DATA INTEGRITY ──
  chk('storage_available', 'localStorage is available and writable', 'storage', 'critical',
    (() => { try { ls.setItem('_bd_test','1'); ls.removeItem('_bd_test'); return true; } catch { return false; } })(),
    'localStorage read/write test passed.',
    'If this fails, the browser may be in private/incognito mode or storage is full.');

  const storageUsed = (() => {
    try {
      let total = 0;
      for (let k in ls) { if (ls.hasOwnProperty(k)) total += (ls[k]||'').length + k.length; }
      return Math.round(total / 1024);
    } catch { return 0; }
  })();
  chk('storage_quota', 'localStorage usage is under 4MB', 'storage', 'medium',
    storageUsed < 4096,
    `Current localStorage usage: ~${storageUsed} KB / ~5120 KB available.`,
    'Archive old exam data or export school data to free up space.');

  chk('platform_creds_exist', 'Platform admin account created', 'storage', 'critical',
    !!creds && !!creds.username,
    creds ? `Platform admin account exists: username="${creds.username}"` : 'No platform credentials found. First-time setup not yet completed.',
    'Navigate to the login screen and create a platform admin account.');

  chk('schools_exist', 'At least one school registered', 'storage', 'high',
    schools.length > 0,
    schools.length > 0 ? `${schools.length} school(s) registered.` : 'No schools found. Login will redirect to platform setup.',
    'Add a school from Platform Admin → Schools tab.');

  const activeSchools = schools.filter(s => s.active !== false);
  chk('schools_active', 'All schools have active status defined', 'storage', 'medium',
    schools.every(s => s.active !== undefined),
    schools.every(s => s.active !== undefined) ? 'All schools have active field set.' : `${schools.filter(s=>s.active===undefined).length} school(s) missing active field — may behave unexpectedly on login.`,
    'Run: platformSchools.forEach(s => { if(s.active===undefined) s.active=true; }); savePlatform();');

  const examDlFee = getExamDlFee ? getExamDlFee() : 0;
  chk('exam_dl_fee', 'Exam download fee configured', 'storage', 'info',
    true,
    `Exam download fee: KES ${examDlFee || 0} (${examDlFee > 0 ? 'paid access enabled' : 'free for all schools'}).`,
    null);

  // ── JS LOGIC / FUNCTION CHECKS ──
  const dupFns = [];
  if (showUnifiedLogin && typeof showUnifiedLogin === 'function') {
    // Can't detect dupes at runtime (last wins), but check for the guard
    const fnSrc = showUnifiedLogin.toString();
    if (!fnSrc.includes('platformSchools.length')) dupFns.push('showUnifiedLogin missing empty-school guard');
  }
  chk('fn_showUnifiedLogin', 'showUnifiedLogin() contains empty-school guard', 'checks', 'critical',
    showUnifiedLogin && showUnifiedLogin.toString().includes('platformSchools.length'),
    showUnifiedLogin && showUnifiedLogin.toString().includes('platformSchools.length')
      ? 'showUnifiedLogin() has the empty-school guard — will redirect to platform setup when no schools exist.'
      : 'showUnifiedLogin() is missing the empty-school guard (duplicate declaration bug). First-time setup redirect is broken.',
    'Apply PATCH 1: merge the empty-school guard from line 350 into the line-406 definition.');

  chk('fn_openPapersTab_revision', 'openPapersTab() initialises Revision tab', 'checks', 'critical',
    typeof openPapersTab === 'function' && openPapersTab.toString().includes('initRevisionTab'),
    typeof openPapersTab === 'function' && openPapersTab.toString().includes('initRevisionTab')
      ? 'openPapersTab() calls initRevisionTab() — Revision tab will load correctly.'
      : 'openPapersTab() does NOT call initRevisionTab() — Revision tab loads blank (duplicate function bug).',
    'Apply PATCH 2: add if (tabId === \'tabRevision\') initRevisionTab(); to the winning openPapersTab() definition.');

  chk('fn_showToast', 'showToast() utility present', 'checks', 'info',
    typeof showToast === 'function',
    typeof showToast === 'function' ? 'showToast() defined at line 7203.' : 'showToast() is missing.',
    null);

  chk('fn_applyRbacPermissions', 'applyRbacPermissions() present', 'checks', 'high',
    typeof applyRbacPermissions === 'function',
    typeof applyRbacPermissions === 'function' ? 'applyRbacPermissions() defined — applied after login.' : 'applyRbacPermissions() is missing — RBAC restrictions will not be applied at login.',
    null);

  chk('fn_enterPlatformDashboard', 'enterPlatformDashboard() sets correct user role', 'checks', 'high',
    typeof enterPlatformDashboard === 'function' && enterPlatformDashboard.toString().includes("role:'platform_admin'"),
    typeof enterPlatformDashboard === 'function' && enterPlatformDashboard.toString().includes("role:'platform_admin'")
      ? 'enterPlatformDashboard() correctly sets role to platform_admin.'
      : 'enterPlatformDashboard() may not set correct role.',
    null);

  chk('fn_gsNameNullSafe', 'saveNewGradingSystem() null-safe gsNewName clear', 'checks', 'medium',
    (() => {
      try {
        const src = saveNewGradingSystem.toString();
        // Check if the .value='' call is wrapped (guarded) or uses optional chaining
        return src.includes('gsNameEl') || src.includes('?.value') || src.includes("getElementById('gsNewName')?.") ;
      } catch { return false; }
    })(),
    'saveNewGradingSystem() — checking if gsNewName clear is null-safe.',
    'Apply PATCH 7: wrap the getElementById(\'gsNewName\').value=\'\' in a null check.');

  return checks;
}

function bdUpdateSummary(results) {
  const counts = { critical:0, high:0, warning:0, pass:0 };
  results.forEach(r => {
    if (r.pass) { counts.pass++; }
    else if (r.sev === 'critical') { counts.critical++; }
    else if (r.sev === 'high') { counts.high++; }
    else { counts.warning++; }
  });
  const el = id => document.getElementById(id);
  if (el('bdCritCount')) el('bdCritCount').textContent = counts.critical;
  if (el('bdHighCount')) el('bdHighCount').textContent = counts.high;
  if (el('bdWarnCount')) el('bdWarnCount').textContent = counts.warning;
  if (el('bdPassCount')) el('bdPassCount').textContent = counts.pass;
}

function bdRenderResults(results) {
  const tab = _bdCurrentTab;
  const filtered = tab === 'checks' ? results
    : tab === 'security' ? results.filter(r => r.cat === 'security')
    : tab === 'rbac'     ? results.filter(r => r.cat === 'rbac')
    : tab === 'storage'  ? results.filter(r => r.cat === 'storage')
    : tab === 'fixes'    ? results.filter(r => !r.pass && r.fix)
    : results;

  if (tab === 'fixes') {
    const content = document.getElementById('bdContent');
    if (!content) return;
    const fixes = filtered;
    if (!fixes.length) {
      content.innerHTML = `<div style="text-align:center;padding:2rem;color:var(--muted)"><i class="fa-solid fa-circle-check" style="color:#10b981;font-size:1.5rem;margin-bottom:.5rem;display:block"></i><div style="font-size:.85rem">No issues with available fixes found.</div></div>`;
      return;
    }
    content.innerHTML = fixes.map((r,i) => `
      <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;margin-bottom:.75rem;padding:1rem 1.1rem">
        <div style="display:flex;align-items:center;gap:.65rem;margin-bottom:.5rem">
          <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${bdSevColor(r.sev)};flex-shrink:0"></span>
          <div style="font-size:.85rem;font-weight:600;color:var(--text);flex:1">${r.label}</div>
          <span style="font-size:.7rem;padding:2px 8px;border-radius:99px;font-weight:600;background:${bdSevBg(r.sev)};color:${bdSevColor(r.sev)}">${r.sev}</span>
        </div>
        <div style="font-size:.78rem;color:var(--muted);margin-bottom:.6rem;line-height:1.5">${r.note}</div>
        <div style="background:var(--input-bg,#f8fafc);border:1px solid var(--border);border-left:3px solid ${bdSevColor(r.sev)};border-radius:6px;padding:.5rem .75rem;font-size:.76rem;color:var(--text);font-family:monospace">${r.fix}</div>
      </div>
    `).join('');
    return;
  }

  const sevOrder = { critical:0, high:1, medium:2, info:3 };
  const sorted = [...filtered].sort((a,b) => {
    if (!a.pass && b.pass) return -1;
    if (a.pass && !b.pass) return 1;
    return (sevOrder[a.sev]||9) - (sevOrder[b.sev]||9);
  });

  const content = document.getElementById('bdContent');
  if (!content) return;

  content.innerHTML = sorted.length ? `
    <div style="border:1px solid var(--border);border-radius:10px;overflow:hidden">
      ${sorted.map(r => `
        <div style="display:flex;align-items:flex-start;gap:.75rem;padding:.8rem 1rem;border-bottom:1px solid var(--border);background:${r.pass?'transparent':'rgba(239,68,68,.03)'}">
          <div style="width:20px;height:20px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:.7rem;font-weight:700;flex-shrink:0;margin-top:1px;background:${r.pass?'#dcfce7':'#fee2e2'};color:${r.pass?'#15803d':'#dc2626'}">
            ${r.pass?'✓':'✗'}
          </div>
          <div style="flex:1;min-width:0">
            <div style="font-size:.82rem;font-weight:600;color:var(--text)">${r.label}</div>
            <div style="font-size:.76rem;color:var(--muted);margin-top:2px;line-height:1.45">${r.note}</div>
            ${!r.pass && r.fix ? `<div style="font-size:.74rem;color:#6366f1;margin-top:.35rem"><i class="fa-solid fa-wrench" style="font-size:.65rem"></i> <em>${r.fix}</em></div>` : ''}
          </div>
          <span style="font-size:.68rem;padding:2px 7px;border-radius:99px;font-weight:600;background:${bdSevBg(r.sev)};color:${bdSevColor(r.sev)};flex-shrink:0;margin-top:2px">${r.sev}</span>
        </div>
      `).join('')}
    </div>
    <div style="margin-top:.75rem;font-size:.76rem;color:var(--muted);text-align:right">${sorted.length} checks shown · ${sorted.filter(r=>r.pass).length} passed · ${sorted.filter(r=>!r.pass).length} failed</div>
  ` : `<div style="text-align:center;padding:2rem;color:var(--muted);font-size:.85rem">No checks in this category.</div>`;
}

function bdSevColor(sev) {
  return sev==='critical'?'#ef4444':sev==='high'?'#f59e0b':sev==='medium'?'#3b82f6':sev==='info'?'#10b981':'#64748b';
}
function bdSevBg(sev) {
  return sev==='critical'?'#fee2e2':sev==='high'?'#fef3c7':sev==='medium'?'#dbeafe':sev==='info'?'#d1fae5':'#f1f5f9';
}


// ══════════════════════════════════════════════════════════════════
// FINANCES — Staff Salary, Payroll, Payslips
// ══════════════════════════════════════════════════════════════════

function calcNetSalary() {
  const basic  = parseFloat(document.getElementById('ssBasic')?.value)       || 0;
  const allow  = parseFloat(document.getElementById('ssAllowances')?.value)  || 0;
  const deduct = parseFloat(document.getElementById('ssDeductions')?.value)  || 0;
  const nhif   = parseFloat(document.getElementById('ssNHIF')?.value)        || 0;
  const nssf   = parseFloat(document.getElementById('ssNSSF')?.value)        || 0;
  const net    = basic + allow - deduct - nhif - nssf;
  const netEl  = document.getElementById('ssNet');
  if (netEl) netEl.value = net.toFixed(2);
}

function loadStaffSalaries() {
  const data = JSON.parse(localStorage.getItem('charanas_staffSalaries') || '[]');
  return data;
}

function saveStaffSalariesToStorage(data) {
  localStorage.setItem('charanas_staffSalaries', JSON.stringify(data));
}

function saveStaffSalary() {
  const staffSel = document.getElementById('ssStaff');
  const name  = staffSel?.options[staffSel.selectedIndex]?.text || '';
  const staffId = staffSel?.value || '';
  const role  = (document.getElementById('ssRole')?.value || '').trim();
  const type  = document.getElementById('ssType')?.value || '';
  const basic = parseFloat(document.getElementById('ssBasic')?.value) || 0;
  const allow = parseFloat(document.getElementById('ssAllowances')?.value) || 0;
  const deduct= parseFloat(document.getElementById('ssDeductions')?.value) || 0;
  const nhif  = parseFloat(document.getElementById('ssNHIF')?.value) || 0;
  const nssf  = parseFloat(document.getElementById('ssNSSF')?.value) || 0;
  const net   = basic + allow - deduct - nhif - nssf;
  const notes = document.getElementById('ssNotes')?.value || '';

  if (!staffId) { alert('Please select a staff member.'); return; }
  if (!basic)   { alert('Please enter a basic salary amount.'); return; }

  let data = loadStaffSalaries();
  const editId = document.getElementById('ssEditId')?.value;
  if (editId) {
    const idx = data.findIndex(r => r.id === editId);
    if (idx > -1) data[idx] = { ...data[idx], name, staffId, role, type, basic, allow, deduct, nhif, nssf, net, notes };
  } else {
    data.push({ id: 'ss_' + Date.now(), name, staffId, role, type, basic, allow, deduct, nhif, nssf, net, notes });
  }
  saveStaffSalariesToStorage(data);
  clearSSForm();
  renderStaffSalaryTable();
  showToast('Salary record saved.');
}

function clearSSForm() {
  ['ssStaff','ssRole','ssType','ssBasic','ssAllowances','ssDeductions','ssNHIF','ssNSSF','ssNet','ssNotes'].forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    if (el.tagName === 'SELECT') el.selectedIndex = 0;
    else el.value = '';
  });
  const editEl = document.getElementById('ssEditId');
  if (editEl) editEl.value = '';
}

function renderStaffSalaryTable() {
  const body = document.getElementById('ssBody');
  if (!body) return;
  const data = loadStaffSalaries();
  if (!data.length) {
    body.innerHTML = '<tr><td colspan="11" style="text-align:center;color:var(--muted);padding:2rem">No salary records yet. Add one above.</td></tr>';
    return;
  }
  body.innerHTML = data.map((r, i) => `
    <tr>
      <td>${i + 1}</td>
      <td>${r.name}</td>
      <td>${r.role || '—'}</td>
      <td><span class="badge">${r.type}</span></td>
      <td>KES ${Number(r.basic).toLocaleString()}</td>
      <td>KES ${Number(r.allow).toLocaleString()}</td>
      <td>KES ${Number(r.deduct).toLocaleString()}</td>
      <td>KES ${Number(r.nhif).toLocaleString()}</td>
      <td>KES ${Number(r.nssf).toLocaleString()}</td>
      <td style="font-weight:700;color:var(--primary)">KES ${Number(r.net).toLocaleString()}</td>
      <td>
        <button class="btn btn-outline btn-xs" onclick="editStaffSalary('${r.id}')"><i class="fa-solid fa-pen"></i></button>
        <button class="btn btn-danger btn-xs" onclick="deleteStaffSalary('${r.id}')"><i class="fa-solid fa-trash"></i></button>
      </td>
    </tr>`).join('');
}

function editStaffSalary(id) {
  const data = loadStaffSalaries();
  const r = data.find(x => x.id === id);
  if (!r) return;
  const editEl = document.getElementById('ssEditId');
  if (editEl) editEl.value = id;
  const staffSel = document.getElementById('ssStaff');
  if (staffSel) staffSel.value = r.staffId;
  ['ssRole','ssBasic','ssAllowances','ssDeductions','ssNHIF','ssNSSF','ssNotes'].forEach(fid => {
    const el = document.getElementById(fid);
    if (!el) return;
    const key = fid.replace('ss','').toLowerCase();
    const map = { role: r.role, basic: r.basic, allowances: r.allow, deductions: r.deduct, nhif: r.nhif, nssf: r.nssf, notes: r.notes };
    el.value = map[key] !== undefined ? map[key] : '';
  });
  const typeEl = document.getElementById('ssType');
  if (typeEl) typeEl.value = r.type;
  calcNetSalary();
  openFeesTab('tabStaffSalary', document.getElementById('tbStaffSalary'));
}

function deleteStaffSalary(id) {
  if (!confirm('Delete this salary record?')) return;
  let data = loadStaffSalaries();
  data = data.filter(r => r.id !== id);
  saveStaffSalariesToStorage(data);
  renderStaffSalaryTable();
  showToast('Salary record deleted.');
}

function exportStaffSalaryCSV() {
  const data = loadStaffSalaries();
  if (!data.length) { alert('No salary records to export.'); return; }
  const rows = [['Name','Role','Type','Basic','Allowances','Deductions','SHA','NSSF','Net Salary']];
  data.forEach(r => rows.push([r.name, r.role, r.type, r.basic, r.allow, r.deduct, r.nhif, r.nssf, r.net]));
  const csv = rows.map(r => r.join(',')).join('\n');
  const a = document.createElement('a');
  a.href = 'data:text/csv,' + encodeURIComponent(csv);
  a.download = 'staff_salaries.csv';
  a.click();
}

// ── Payroll ──

function generatePayroll() {
  const month = document.getElementById('prMonth')?.value || '';
  const year  = document.getElementById('prYear')?.value  || '';
  const salaries = loadStaffSalaries();
  const body = document.getElementById('payrollBody');
  const statsEl = document.getElementById('payrollSummaryStats');

  if (!salaries.length) {
    if (body) body.innerHTML = '<tr><td colspan="11" style="text-align:center;color:var(--muted);padding:2rem">No staff salary records found. Add salaries under <strong>Staff Salary</strong> tab first.</td></tr>';
    return;
  }

  const totalNet = salaries.reduce((s, r) => s + Number(r.net), 0);
  const totalBasic = salaries.reduce((s, r) => s + Number(r.basic), 0);

  if (statsEl) {
    statsEl.innerHTML = `
      <div class="fee-stat-card"><div class="fsc-label">Total Staff</div><div class="fsc-val">${salaries.length}</div></div>
      <div class="fee-stat-card"><div class="fsc-label">Total Basic (KES)</div><div class="fsc-val">${totalBasic.toLocaleString()}</div></div>
      <div class="fee-stat-card" style="border-color:var(--primary)"><div class="fsc-label">Total Net Payroll (KES)</div><div class="fsc-val" style="color:var(--primary)">${totalNet.toLocaleString()}</div></div>
      <div class="fee-stat-card"><div class="fsc-label">Period</div><div class="fsc-val" style="font-size:.9rem">${month} ${year}</div></div>`;
  }

  if (body) {
    body.innerHTML = salaries.map((r, i) => `
      <tr>
        <td>${i + 1}</td>
        <td>${r.name}</td>
        <td>${r.role || '—'}</td>
        <td>KES ${Number(r.basic).toLocaleString()}</td>
        <td>KES ${Number(r.allow).toLocaleString()}</td>
        <td>KES ${Number(r.nhif).toLocaleString()}</td>
        <td>KES ${Number(r.nssf).toLocaleString()}</td>
        <td>KES ${Number(r.deduct).toLocaleString()}</td>
        <td style="font-weight:700;color:var(--primary)">KES ${Number(r.net).toLocaleString()}</td>
        <td><span class="badge badge-green">Pending</span></td>
        <td><button class="btn btn-outline btn-xs" onclick="markPaid(this)">Mark Paid</button></td>
      </tr>`).join('');
  }
  showToast(`Payroll generated for ${month} ${year}.`);
}

function markPaid(btn) {
  const row = btn.closest('tr');
  const statusCell = row.cells[9];
  statusCell.innerHTML = '<span class="badge badge-green" style="background:#16a34a">Paid</span>';
  btn.textContent = '✓ Paid';
  btn.disabled = true;
  btn.classList.add('btn-primary');
}

function printPayroll() {
  const month = document.getElementById('prMonth')?.value || '';
  const year  = document.getElementById('prYear')?.value  || '';
  const rows  = document.getElementById('payrollBody')?.innerHTML || '';
  if (!rows || rows.includes('No staff')) { alert('Generate payroll first.'); return; }
  const win = window.open('', '_blank');
  win.document.write(`<!DOCTYPE html><html><head><title>Payroll — ${month} ${year}</title>
  <style>body{font-family:Arial,sans-serif;padding:20px}table{width:100%;border-collapse:collapse}th,td{border:1px solid #ddd;padding:8px;font-size:12px}th{background:#f5f5f5}</style>
  </head><body><h2 style="text-align:center">Payroll — ${month} ${year}</h2>
  <table><thead><tr><th>#</th><th>Name</th><th>Role</th><th>Basic</th><th>Allowances</th><th>SHA</th><th>NSSF</th><th>Deductions</th><th>Net Pay</th><th>Status</th></tr></thead>
  <tbody>${rows}</tbody></table></body></html>`);
  win.document.close();
  win.print();
}

// ── Payslips ──

function onPsStaffChange() {
  // Could pre-fill salary info when staff is selected
}

function previewPayslip() {
  const staffSel = document.getElementById('psStaff');
  const staffId = staffSel?.value;
  const staffName = staffSel?.options[staffSel.selectedIndex]?.text || '';
  const month = document.getElementById('psMonth')?.value || '';
  const year  = document.getElementById('psYear')?.value  || '';
  const area  = document.getElementById('payslipPreviewArea');
  if (!area) return;

  if (!staffId) { area.innerHTML = '<p style="color:var(--muted)">Please select a staff member.</p>'; return; }

  const salaries = loadStaffSalaries();
  const rec = salaries.find(r => r.staffId === staffId);
  if (!rec) {
    area.innerHTML = `<p style="color:var(--muted)">No salary record found for <strong>${staffName}</strong>. Please add their salary under the <strong>Staff Salary</strong> tab first.</p>`;
    return;
  }

  const school = localStorage.getItem('charanas_schoolName') || 'School Name';
  area.innerHTML = `
    <div style="border:1px solid var(--border);border-radius:8px;padding:1.5rem;width:100%;font-size:.85rem">
      <div style="text-align:center;margin-bottom:1rem;border-bottom:2px solid var(--primary);padding-bottom:.75rem">
        <div style="font-size:1.1rem;font-weight:800;color:var(--primary)">${school}</div>
        <div style="font-size:.9rem;font-weight:600;margin-top:.2rem">PAYSLIP — ${month.toUpperCase()} ${year}</div>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:.5rem;margin-bottom:1rem">
        <div><span style="color:var(--muted)">Employee:</span> <strong>${rec.name}</strong></div>
        <div><span style="color:var(--muted)">Role:</span> ${rec.role || '—'}</div>
        <div><span style="color:var(--muted)">Employment Type:</span> ${rec.type}</div>
        <div><span style="color:var(--muted)">Pay Period:</span> ${month} ${year}</div>
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:.82rem">
        <thead><tr style="background:var(--bg-muted)"><th style="padding:.4rem .6rem;text-align:left;border:1px solid var(--border)">Description</th><th style="padding:.4rem .6rem;text-align:right;border:1px solid var(--border)">Amount (KES)</th></tr></thead>
        <tbody>
          <tr><td style="padding:.4rem .6rem;border:1px solid var(--border)">Basic Salary</td><td style="padding:.4rem .6rem;text-align:right;border:1px solid var(--border)">${Number(rec.basic).toLocaleString()}</td></tr>
          <tr><td style="padding:.4rem .6rem;border:1px solid var(--border)">Allowances</td><td style="padding:.4rem .6rem;text-align:right;border:1px solid var(--border)">${Number(rec.allow).toLocaleString()}</td></tr>
          <tr style="background:#fef2f2"><td style="padding:.4rem .6rem;border:1px solid var(--border)">SHA</td><td style="padding:.4rem .6rem;text-align:right;border:1px solid var(--border);color:#ef4444">- ${Number(rec.nhif).toLocaleString()}</td></tr>
          <tr style="background:#fef2f2"><td style="padding:.4rem .6rem;border:1px solid var(--border)">NSSF</td><td style="padding:.4rem .6rem;text-align:right;border:1px solid var(--border);color:#ef4444">- ${Number(rec.nssf).toLocaleString()}</td></tr>
          <tr style="background:#fef2f2"><td style="padding:.4rem .6rem;border:1px solid var(--border)">Other Deductions</td><td style="padding:.4rem .6rem;text-align:right;border:1px solid var(--border);color:#ef4444">- ${Number(rec.deduct).toLocaleString()}</td></tr>
          <tr style="background:var(--bg-muted);font-weight:700"><td style="padding:.4rem .6rem;border:1px solid var(--border)">NET PAY</td><td style="padding:.4rem .6rem;text-align:right;border:1px solid var(--border);color:var(--primary);font-size:1rem">KES ${Number(rec.net).toLocaleString()}</td></tr>
        </tbody>
      </table>
      <div style="margin-top:1rem;font-size:.75rem;color:var(--muted);text-align:center">Generated by Charanas School Management System</div>
    </div>`;

  // Save to history
  let history = JSON.parse(localStorage.getItem('charanas_payslipHistory') || '[]');
  const existing = history.find(h => h.staffId === staffId && h.month === month && h.year === year);
  if (!existing) {
    history.push({ id: 'ps_' + Date.now(), staffId, name: rec.name, role: rec.role || '', month, year, net: rec.net,
      basic: rec.basic, allow: rec.allow, nhif: rec.nhif, nssf: rec.nssf, deduct: rec.deduct, type: rec.type || '' });
    localStorage.setItem('charanas_payslipHistory', JSON.stringify(history));
    renderPayslipHistory();
  }
}

function printPayslip() {
  const area = document.getElementById('payslipPreviewArea');
  if (!area || area.innerHTML.includes('Select a staff')) { alert('Preview a payslip first.'); return; }
  const win = window.open('', '_blank');
  win.document.write(`<!DOCTYPE html><html><head><title>Payslip</title>
  <style>body{font-family:Arial,sans-serif;padding:30px;max-width:600px;margin:auto}table{width:100%;border-collapse:collapse}th,td{border:1px solid #ddd;padding:8px;font-size:12px}</style>
  </head><body>${area.innerHTML}</body></html>`);
  win.document.close();
  win.print();
}

function renderPayslipHistory() {
  const body = document.getElementById('payslipHistBody');
  if (!body) return;
  let history = JSON.parse(localStorage.getItem('charanas_payslipHistory') || '[]');
  const staffFilter = document.getElementById('psHistStaff')?.value || '';
  const yearFilter  = document.getElementById('psHistYear')?.value  || '';
  if (staffFilter) history = history.filter(h => h.staffId === staffFilter);
  if (yearFilter)  history = history.filter(h => h.year === yearFilter);
  if (!history.length) {
    body.innerHTML = '<tr><td colspan="7" style="text-align:center;color:var(--muted);padding:2rem">No payslips generated yet.</td></tr>';
    return;
  }
  body.innerHTML = history.map((h, i) => `
    <tr>
      <td>${i + 1}</td>
      <td>${h.name}</td>
      <td>${h.role || '—'}</td>
      <td>${h.month}</td>
      <td>${h.year}</td>
      <td style="font-weight:700;color:var(--primary)">KES ${Number(h.net).toLocaleString()}</td>
      <td>
        <button class="btn btn-outline btn-xs" onclick="reloadPayslip('${h.staffId}','${h.month}','${h.year}')"><i class="fa-solid fa-eye"></i> View</button>
        <button class="btn btn-outline btn-xs" style="border-color:#7c3aed;color:#7c3aed;margin-left:.3rem" onclick="reloadAndPrintPayslip('${h.staffId}','${h.month}','${h.year}')"><i class="fa-solid fa-print"></i> Print</button>
        <button class="btn btn-danger btn-xs" style="margin-left:.3rem" onclick="deletePayslipHistory('${h.id}')"><i class="fa-solid fa-trash"></i></button>
      </td>
    </tr>`).join('');
}

function reloadPayslip(staffId, month, year) {
  const staffSel = document.getElementById('psStaff');
  if (staffSel) staffSel.value = staffId;
  const monthSel = document.getElementById('psMonth');
  if (monthSel) monthSel.value = month;
  const yearEl = document.getElementById('psYear');
  if (yearEl) yearEl.value = year;
  openFeesTab('tabPayslips', document.getElementById('tbPayslips'));
  previewPayslip();
}

function reloadAndPrintPayslip(staffId, month, year) {
  // Build and print the payslip PDF directly using the shared _sppBuildPDF builder
  const salaries = loadStaffSalaries();
  const rec = salaries.find(r => r.staffId === staffId);
  const pHistory = JSON.parse(localStorage.getItem('charanas_payslipHistory') || '[]');
  const ph = pHistory.find(h => h.staffId === staffId && h.month === month && h.year === String(year) && h.basic != null);
  const school = localStorage.getItem('charanas_schoolName') || (typeof settings !== 'undefined' && settings.schoolName) || 'School';
  let pay = null;
  if (rec) {
    pay = { name: rec.name, role: rec.role || '—', type: rec.type || '—', staffId,
            basic: Number(rec.basic||0), allow: Number(rec.allow||0), nhif: Number(rec.nhif||0),
            nssf: Number(rec.nssf||0), deduct: Number(rec.deduct||0), net: Number(rec.net||0),
            status: '', source: 'salary' };
  } else if (ph) {
    pay = { name: ph.name, role: ph.role || '—', type: ph.type || '—', staffId,
            basic: Number(ph.basic||0), allow: Number(ph.allow||0), nhif: Number(ph.nhif||0),
            nssf: Number(ph.nssf||0), deduct: Number(ph.deduct||0), net: Number(ph.net||0),
            status: '', source: 'salary' };
  }
  if (!pay) { alert('Salary record not found for this staff member. Please preview first.'); reloadPayslip(staffId, month, year); return; }
  // Temporarily set currentUser so _sppBuildPDF can use staffId/dept
  const prevUser = typeof currentUser !== 'undefined' ? currentUser : null;
  if (!window.currentUser) window.currentUser = {};
  const savedId = window.currentUser.staffId; const savedDept = window.currentUser.dept;
  window.currentUser.staffId = staffId;
  window.currentUser.dept = (rec && rec.dept) || '—';
  try {
    const doc = _sppBuildPDF(month, year, pay, school);
    const blobUrl = doc.output('bloburl');
    const win = window.open(blobUrl, '_blank');
    if (win) win.onload = () => { try { win.print(); } catch(e){} };
    else { alert('Allow pop-ups to print, or use the View button and print from there.'); }
  } finally {
    window.currentUser.staffId = savedId;
    window.currentUser.dept = savedDept;
  }
}

function deletePayslipHistory(id) {
  if (!confirm('Remove this payslip from history?')) return;
  let history = JSON.parse(localStorage.getItem('charanas_payslipHistory') || '[]');
  history = history.filter(h => h.id !== id);
  localStorage.setItem('charanas_payslipHistory', JSON.stringify(history));
  renderPayslipHistory();
}

