function loadStaffLeave() {
  return JSON.parse(localStorage.getItem(staffLeaveKey()) || '[]');
}
function saveStaffLeave(data) {
  localStorage.setItem(staffLeaveKey(), JSON.stringify(data));
}

function sdpPopulateLeaveDropdowns() {
  const staff = loadStaffDetails();
  ['sdpLeaveStaff', 'sdpLeaveFilterStaff'].forEach(id => {
    const sel = document.getElementById(id);
    if (!sel) return;
    const first = id === 'sdpLeaveFilterStaff' ? '<option value="">All Staff</option>' : '<option value="">— Select Staff —</option>';
    sel.innerHTML = first + staff.map(s => `<option value="${s.id}">${s.name}</option>`).join('');
  });
}

function sdpPopulateDocDropdownSchool() {
  const staff = loadStaffDetails();
  const sel = document.getElementById('sdpdocStaff');
  if (!sel) return;
  sel.innerHTML = '<option value="">— Select Staff —</option>' + staff.map(s => `<option value="${s.id}">${s.name}</option>`).join('');
}

/* Auto-calculate days when dates change */
function sdpLeaveCalcDays() {
  const s = document.getElementById('sdpLeaveStart')?.value;
  const e = document.getElementById('sdpLeaveEnd')?.value;
  if (s && e) {
    const diff = Math.round((new Date(e) - new Date(s)) / 86400000) + 1;
    const el = document.getElementById('sdpLeaveDays');
    if (el) el.value = diff > 0 ? diff : '';
  }
}

function sdpSaveLeave() {
  const g = id => (document.getElementById(id)?.value || '').trim();
  const staffId = g('sdpLeaveStaff');
  const start   = g('sdpLeaveStart');
  const end     = g('sdpLeaveEnd');
  if (!staffId) { alert('Please select a staff member.'); return; }
  if (!start)   { alert('Start date is required.'); return; }
  if (!end)     { alert('End date is required.'); return; }
  if (new Date(end) < new Date(start)) { alert('End date cannot be before start date.'); return; }
  const staffList = loadStaffDetails();
  const staffRec  = staffList.find(s => s.id === staffId);
  const rec = {
    staffId, staffName: staffRec ? staffRec.name : '—',
    type:   document.getElementById('sdpLeaveType')?.value   || 'Annual Leave',
    status: document.getElementById('sdpLeaveStatus')?.value || 'Pending',
    start, end,
    days:   document.getElementById('sdpLeaveDays')?.value   || '',
    reason: g('sdpLeaveReason')
  };
  let data = loadStaffLeave();
  const editId = g('sdpLeaveEditId');
  if (editId) {
    const idx = data.findIndex(r => r.id === editId);
    if (idx > -1) data[idx] = { ...data[idx], ...rec };
  } else {
    data.push({ id: 'lv_' + Date.now(), ...rec });
  }
  saveStaffLeave(data);
  sdpClearLeave();
  sdpRenderLeaveList();
  showToast('Leave record saved.');
}

function sdpClearLeave() {
  ['sdpLeaveEditId','sdpLeaveStart','sdpLeaveEnd','sdpLeaveDays','sdpLeaveReason'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  ['sdpLeaveStaff','sdpLeaveType','sdpLeaveStatus'].forEach(id => {
    const el = document.getElementById(id); if (el) el.selectedIndex = 0;
  });
}

function sdpEditLeave(id) {
  const r = loadStaffLeave().find(x => x.id === id);
  if (!r) return;
  document.getElementById('sdpLeaveEditId').value = id;
  ['sdpLeaveStaff','sdpLeaveType','sdpLeaveStatus'].forEach(fid => {
    const key = {sdpLeaveStaff:'staffId',sdpLeaveType:'type',sdpLeaveStatus:'status'}[fid];
    const el = document.getElementById(fid); if (el && r[key]) el.value = r[key];
  });
  ['sdpLeaveStart','sdpLeaveEnd','sdpLeaveDays','sdpLeaveReason'].forEach(fid => {
    const key = {sdpLeaveStart:'start',sdpLeaveEnd:'end',sdpLeaveDays:'days',sdpLeaveReason:'reason'}[fid];
    const el = document.getElementById(fid); if (el) el.value = r[key] || '';
  });
  openSDTab('sdpLeave', document.getElementById('sdpbtLeave'));
}

function sdpDeleteLeave(id) {
  if (!confirm('Delete this leave record?')) return;
  saveStaffLeave(loadStaffLeave().filter(r => r.id !== id));
  sdpRenderLeaveList();
  showToast('Leave record deleted.');
}

function sdpRenderLeaveList() {
  const el = document.getElementById('sdpLeaveList'); if (!el) return;
  let data = loadStaffLeave();
  const filterStaff  = document.getElementById('sdpLeaveFilterStaff')?.value  || '';
  const filterStatus = document.getElementById('sdpLeaveFilterStatus')?.value || '';
  if (filterStaff)  data = data.filter(r => r.staffId  === filterStaff);
  if (filterStatus) data = data.filter(r => r.status   === filterStatus);
  if (!data.length) {
    el.innerHTML = '<p style="color:var(--muted);font-size:.85rem;text-align:center;padding:2rem">No leave records found.</p>';
    return;
  }
  const sc = { Pending:'#f59e0b', Approved:'#16a34a', Rejected:'#ef4444', Completed:'#6b7280' };
  el.innerHTML = `<div class="tbl-wrap"><table>
    <thead><tr><th>#</th><th>Staff</th><th>Type</th><th>Start</th><th>End</th><th>Days</th><th>Status</th><th>Reason</th><th>Action</th></tr></thead>
    <tbody>${data.map((r,i)=>`<tr>
      <td>${i+1}</td><td><strong>${r.staffName}</strong></td><td>${r.type}</td>
      <td>${r.start}</td><td>${r.end}</td><td>${r.days||'—'}</td>
      <td><span class="badge" style="background:${sc[r.status]||'#6b7280'};color:#fff">${r.status}</span></td>
      <td>${r.reason||'—'}</td>
      <td style="white-space:nowrap">
        <button class="btn btn-outline btn-xs" onclick="sdpEditLeave('${r.id}')"><i class="fa-solid fa-pen"></i></button>
        <button class="btn btn-danger btn-xs"  onclick="sdpDeleteLeave('${r.id}')"><i class="fa-solid fa-trash"></i></button>
      </td>
    </tr>`).join('')}</tbody></table></div>`;
}

// ── Staff Details: school-side only (see s-staffdetails section) ─







// ═══════════════════════════════════════════════════════════════
//  HR & PAYROLL MODULE
// ═══════════════════════════════════════════════════════════════

function loadPayrollData()  { return JSON.parse(localStorage.getItem('charanas_payroll')||'[]'); }
function savePayrollData(d) { localStorage.setItem('charanas_payroll', JSON.stringify(d)); }
function loadLeaveData()    { return JSON.parse(localStorage.getItem('charanas_leave')||'[]'); }
function saveLeaveData(d)   { localStorage.setItem('charanas_leave', JSON.stringify(d)); }

function openPlatHRTab(tabId, btn) {
  document.querySelectorAll('#platTab-hrpayroll .tab-panel').forEach(p => { p.style.display='none'; p.classList.remove('active'); });
  document.querySelectorAll('#platHRTabBar .tb').forEach(b => b.classList.remove('active'));
  const panel = document.getElementById(tabId);
  if (panel) { panel.style.display=''; panel.classList.add('active'); }
  if (btn) btn.classList.add('active');
}

function platInitHRPayroll() {
  platRenderHRStats();
  platRenderPayrollList();
  platRenderLeaveList();
  platPopulateHRDropdowns();
}

function platPopulateHRDropdowns() {
  const staff = loadStaffDetails();
  const opts = '<option value="">— Select Staff —</option>' +
    staff.map(s => `<option value="${s.id}">${s.name}${s.role ? ' — '+s.role : ''}</option>`).join('');
  ['hrpStaff','hrlStaff','hrpsStaff'].forEach(id => {
    const el = document.getElementById(id); if (el) el.innerHTML = opts;
  });
}

function platRenderHRStats() {
  const el = document.getElementById('platHRStats'); if (!el) return;
  const pay = loadPayrollData();
  const lv  = loadLeaveData();
  const staff = loadStaffDetails();
  const totalNet = pay.reduce((a,r) => a + (Number(r.basic||0) + Number(r.allowances||0) - Number(r.deductions||0)), 0);
  const paid = pay.filter(r => r.status === 'Paid').length;
  el.innerHTML = `
    <div class="fee-stat-card"><div class="fsc-label">Payroll Records</div><div class="fsc-val">${pay.length}</div></div>
    <div class="fee-stat-card"><div class="fsc-label">Paid</div><div class="fsc-val" style="color:#16a34a">${paid}</div></div>
    <div class="fee-stat-card"><div class="fsc-label">Total Net Pay (KES)</div><div class="fsc-val">${totalNet.toLocaleString()}</div></div>
    <div class="fee-stat-card"><div class="fsc-label">Leave Records</div><div class="fsc-val">${lv.length}</div></div>`;
}

function platSavePayroll() {
  const g = id => (document.getElementById(id)?.value||'').trim();
  const staffSel = document.getElementById('hrpStaff');
  const staffName = staffSel?.options[staffSel.selectedIndex]?.text || '';
  const staffId   = staffSel?.value || '';
  const period    = g('hrpPeriod');
  const basic     = Number(g('hrpBasic'));
  if (!staffId) { showToast('Please select a staff member.'); return; }
  if (!period)  { showToast('Please select a pay period.'); return; }
  if (!basic)   { showToast('Basic salary is required.'); return; }
  const rec = {
    staffId, staffName, period,
    basic, allowances: Number(g('hrpAllowances')||0),
    deductions: Number(g('hrpDeductions')||0),
    status: document.getElementById('hrpStatus')?.value || 'Pending',
    notes: g('hrpNotes')
  };
  const net = rec.basic + rec.allowances - rec.deductions;
  if (net < 0) { showToast('Net pay cannot be negative. Check deductions.'); return; }
  const editId = g('hrpEditId');
  let data = loadPayrollData();
  if (editId) {
    const idx = data.findIndex(r => r.id === editId);
    if (idx > -1) data[idx] = { ...data[idx], ...rec };
  } else {
    data.push({ id: 'pay_'+Date.now(), ...rec });
  }
  savePayrollData(data);
  platClearPayrollForm();
  platRenderPayrollList();
  platRenderHRStats();
  showToast('Payroll record saved.');
}

function platClearPayrollForm() {
  ['hrpEditId','hrpBasic','hrpNotes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  ['hrpAllowances','hrpDeductions'].forEach(id => { const el=document.getElementById(id); if(el) el.value='0'; });
  const p=document.getElementById('hrpPeriod'); if(p) p.value='';
  const s=document.getElementById('hrpStaff'); if(s) s.selectedIndex=0;
  const st=document.getElementById('hrpStatus'); if(st) st.selectedIndex=0;
}

function platRenderPayrollList() {
  const body = document.getElementById('hrPayrollBody'); if (!body) return;
  let data = loadPayrollData();
  const search = (document.getElementById('hrpSearch')?.value||'').toLowerCase();
  const filterStatus = document.getElementById('hrpFilterStatus')?.value||'';
  if (search) data = data.filter(r => (r.staffName+r.period).toLowerCase().includes(search));
  if (filterStatus) data = data.filter(r => r.status === filterStatus);
  if (!data.length) {
    body.innerHTML = '<tr><td colspan="9" style="text-align:center;color:var(--muted);padding:2rem">No payroll records found.</td></tr>';
    return;
  }
  const sc = { Paid:'#16a34a', Pending:'#f59e0b', 'On Hold':'#ef4444' };
  body.innerHTML = data.map((r,i) => {
    const net = (Number(r.basic)||0) + (Number(r.allowances)||0) - (Number(r.deductions)||0);
    return `<tr>
      <td>${i+1}</td>
      <td><strong>${r.staffName}</strong></td>
      <td>${r.period}</td>
      <td>${Number(r.basic).toLocaleString()}</td>
      <td style="color:#16a34a">+${Number(r.allowances||0).toLocaleString()}</td>
      <td style="color:#ef4444">-${Number(r.deductions||0).toLocaleString()}</td>
      <td><strong>${net.toLocaleString()}</strong></td>
      <td><span class="badge" style="background:${sc[r.status]||'#6b7280'};color:#fff">${r.status}</span></td>
      <td>
        <button class="btn btn-outline btn-xs" onclick="platEditPayroll('${r.id}')"><i class="fa-solid fa-pen"></i></button>
        <button class="btn btn-danger btn-xs"  onclick="platDeletePayroll('${r.id}')"><i class="fa-solid fa-trash"></i></button>
      </td>
    </tr>`;
  }).join('');
}

function platEditPayroll(id) {
  const r = loadPayrollData().find(x => x.id === id); if (!r) return;
  const s = id => document.getElementById(id);
  if (s('hrpEditId'))    s('hrpEditId').value    = r.id;
  if (s('hrpPeriod'))    s('hrpPeriod').value     = r.period;
  if (s('hrpBasic'))     s('hrpBasic').value      = r.basic;
  if (s('hrpAllowances'))s('hrpAllowances').value = r.allowances||0;
  if (s('hrpDeductions'))s('hrpDeductions').value = r.deductions||0;
  if (s('hrpNotes'))     s('hrpNotes').value      = r.notes||'';
  if (s('hrpStaff'))     s('hrpStaff').value      = r.staffId;
  if (s('hrpStatus'))    s('hrpStatus').value      = r.status;
  openPlatHRTab('hrPayroll', document.getElementById('hrtbPayroll'));
  showToast('Editing payroll record — make changes and save.');
}

function platDeletePayroll(id) {
  if (!confirm('Delete this payroll record?')) return;
  savePayrollData(loadPayrollData().filter(r => r.id !== id));
  platRenderPayrollList(); platRenderHRStats();
  showToast('Payroll record deleted.');
}

function platExportPayrollCSV() {
  const data = loadPayrollData();
  if (!data.length) { showToast('No payroll records to export.'); return; }
  const rows = [['#','Staff','Period','Basic','Allowances','Deductions','Net Pay','Status','Notes']];
  data.forEach((r,i) => {
    const net = (Number(r.basic)||0)+(Number(r.allowances)||0)-(Number(r.deductions)||0);
    rows.push([i+1,r.staffName,r.period,r.basic,r.allowances||0,r.deductions||0,net,r.status,r.notes||'']);
  });
  const csv = rows.map(r => r.map(c => '"'+String(c).replace(/"/g,'""')+'"').join(',')).join('\n');
  const a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,\uFEFF'+encodeURIComponent(csv);
  a.download = 'payroll_export.csv'; a.click();
}

// ─ LEAVE ─

function platSaveLeave() {
  const g = id => (document.getElementById(id)?.value||'').trim();
  const staffSel  = document.getElementById('hrlStaff');
  const staffName = staffSel?.options[staffSel.selectedIndex]?.text||'';
  const staffId   = staffSel?.value||'';
  const start = g('hrlStart'), end = g('hrlEnd');
  if (!staffId) { showToast('Please select a staff member.'); return; }
  if (!start)   { showToast('Start date is required.'); return; }
  if (!end)     { showToast('End date is required.'); return; }
  if (end < start) { showToast('End date cannot be before start date.'); return; }
  const days = Math.round((new Date(end)-new Date(start))/(1000*60*60*24))+1;
  const rec = {
    staffId, staffName,
    type:   document.getElementById('hrlType')?.value||'Annual Leave',
    status: document.getElementById('hrlStatus')?.value||'Pending',
    start, end, days,
    reason: g('hrlReason')
  };
  const editId = g('hrlEditId');
  let data = loadLeaveData();
  if (editId) {
    const idx = data.findIndex(r=>r.id===editId);
    if (idx>-1) data[idx]={...data[idx],...rec};
  } else {
    data.push({id:'lv_'+Date.now(),...rec});
  }
  saveLeaveData(data);
  ['hrlEditId','hrlStart','hrlEnd','hrlReason'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
  document.getElementById('hrlStaff').selectedIndex=0;
  platRenderLeaveList(); platRenderHRStats();
  showToast('Leave record saved.');
}

function platRenderLeaveList() {
  const body = document.getElementById('hrLeaveBody'); if (!body) return;
  const data = loadLeaveData();
  if (!data.length) {
    body.innerHTML='<tr><td colspan="9" style="text-align:center;color:var(--muted);padding:2rem">No leave records yet.</td></tr>';
    return;
  }
  const sc={Approved:'#16a34a',Pending:'#f59e0b',Rejected:'#ef4444'};
  body.innerHTML=data.map((r,i)=>`<tr>
    <td>${i+1}</td><td><strong>${r.staffName}</strong></td><td>${r.type}</td>
    <td>${r.start}</td><td>${r.end}</td><td>${r.days}</td>
    <td><span class="badge" style="background:${sc[r.status]||'#6b7280'};color:#fff">${r.status}</span></td>
    <td>${r.reason||'—'}</td>
    <td>
      <button class="btn btn-outline btn-xs" onclick="platEditLeave('${r.id}')"><i class="fa-solid fa-pen"></i></button>
      <button class="btn btn-danger btn-xs"  onclick="platDeleteLeave('${r.id}')"><i class="fa-solid fa-trash"></i></button>
    </td>
  </tr>`).join('');
}

function platEditLeave(id) {
  const r=loadLeaveData().find(x=>x.id===id); if(!r) return;
  const s=id=>document.getElementById(id);
  if(s('hrlEditId'))  s('hrlEditId').value  =r.id;
  if(s('hrlStaff'))   s('hrlStaff').value   =r.staffId;
  if(s('hrlType'))    s('hrlType').value     =r.type;
  if(s('hrlStatus'))  s('hrlStatus').value   =r.status;
  if(s('hrlStart'))   s('hrlStart').value    =r.start;
  if(s('hrlEnd'))     s('hrlEnd').value      =r.end;
  if(s('hrlReason'))  s('hrlReason').value   =r.reason||'';
  openPlatHRTab('hrLeave', document.getElementById('hrtbLeave'));
}

function platDeleteLeave(id) {
  if(!confirm('Delete this leave record?')) return;
  saveLeaveData(loadLeaveData().filter(r=>r.id!==id));
  platRenderLeaveList(); platRenderHRStats();
  showToast('Leave record deleted.');
}

// ─ PAYSLIPS ─

function platGeneratePayslip() {
  const staffSel = document.getElementById('hrpsStaff');
  const staffId  = staffSel?.value||'';
  const staffName= staffSel?.options[staffSel.selectedIndex]?.text||'';
  const period   = document.getElementById('hrpsPeriod')?.value||'';
  if (!staffId||!period) { showToast('Select a staff member and period.'); return; }
  const allPay = loadPayrollData();
  const rec = allPay.find(r=>r.staffId===staffId && r.period===period);
  const out = document.getElementById('platPayslipOutput'); if(!out) return;
  if (!rec) {
    out.innerHTML='<p style="color:var(--muted);font-size:.85rem">No payroll record found for this staff and period.</p>';
    return;
  }
  const net = (Number(rec.basic)||0)+(Number(rec.allowances)||0)-(Number(rec.deductions)||0);
  const staffRec = loadStaffDetails().find(r=>r.id===staffId)||{};
  out.innerHTML=`
    <div style="border:2px solid var(--border);border-radius:12px;padding:1.5rem;max-width:560px;font-size:.88rem" id="payslipPrintArea">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:1.25rem;padding-bottom:.75rem;border-bottom:2px solid var(--border)">
        <div>
          <div style="font-size:1.2rem;font-weight:800;color:var(--primary)">PAYSLIP</div>
          <div style="font-size:.78rem;color:var(--muted)">Pay Period: <strong>${rec.period}</strong></div>
        </div>
        <div style="text-align:right;font-size:.78rem;color:var(--muted)">
          <div><strong>Charanas Platform</strong></div>
          <div>Generated: ${new Date().toLocaleDateString()}</div>
        </div>
      </div>
      <div style="margin-bottom:1rem">
        <div style="font-weight:700;font-size:.95rem">${staffName}</div>
        <div style="color:var(--muted)">${staffRec.role||'—'} · ${staffRec.dept||'—'}</div>
        <div style="color:var(--muted)">Staff ID: ${staffRec.staffId||'—'}</div>
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:.85rem">
        <tr style="background:var(--bg)"><td style="padding:.5rem .75rem;border:1px solid var(--border)">Basic Salary</td><td style="padding:.5rem .75rem;border:1px solid var(--border);text-align:right">KES ${Number(rec.basic).toLocaleString()}</td></tr>
        <tr><td style="padding:.5rem .75rem;border:1px solid var(--border);color:#16a34a">Allowances</td><td style="padding:.5rem .75rem;border:1px solid var(--border);text-align:right;color:#16a34a">+ KES ${Number(rec.allowances||0).toLocaleString()}</td></tr>
        <tr><td style="padding:.5rem .75rem;border:1px solid var(--border);color:#ef4444">Deductions</td><td style="padding:.5rem .75rem;border:1px solid var(--border);text-align:right;color:#ef4444">- KES ${Number(rec.deductions||0).toLocaleString()}</td></tr>
        <tr style="background:var(--primary);color:#fff"><td style="padding:.6rem .75rem;font-weight:700">NET PAY</td><td style="padding:.6rem .75rem;text-align:right;font-weight:700">KES ${net.toLocaleString()}</td></tr>
      </table>
      ${rec.status==='Paid'?'<div style="margin-top:.75rem;padding:.4rem .8rem;background:#dcfce7;color:#15803d;border-radius:6px;font-size:.78rem;font-weight:700;display:inline-block">✓ PAID</div>':'<div style="margin-top:.75rem;padding:.4rem .8rem;background:#fef9c3;color:#854d0e;border-radius:6px;font-size:.78rem;font-weight:700;display:inline-block">PENDING PAYMENT</div>'}
      ${rec.notes?`<div style="margin-top:.75rem;font-size:.78rem;color:var(--muted)"><strong>Notes:</strong> ${rec.notes}</div>`:''}
    </div>
    <button class="btn btn-outline btn-sm" style="margin-top:.75rem" onclick="window.print()"><i class="fa-solid fa-print"></i> Print Payslip</button>`;
}

// ═══════════════════════════════════════════════════════════════
//  REPORTS MODULE
// ═══════════════════════════════════════════════════════════════

function platInitReports() {
  const staff   = loadStaffDetails();
  const pay     = loadPayrollData();
  const lv      = loadLeaveData();
  const docs    = JSON.parse(localStorage.getItem(staffDocsKey())||'[]');

  // ── KPIs ──
  const kpiEl = document.getElementById('platReportKPIs');
  if (kpiEl) {
    const totalNet = pay.reduce((a,r)=>a+(Number(r.basic||0)+Number(r.allowances||0)-Number(r.deductions||0)),0);
    kpiEl.innerHTML = `
      <div class="fee-stat-card"><div class="fsc-label">Total Staff</div><div class="fsc-val">${staff.length}</div></div>
      <div class="fee-stat-card"><div class="fsc-label">Active Staff</div><div class="fsc-val" style="color:#16a34a">${staff.filter(r=>r.status==='Active').length}</div></div>
      <div class="fee-stat-card"><div class="fsc-label">Payroll Records</div><div class="fsc-val">${pay.length}</div></div>
      <div class="fee-stat-card"><div class="fsc-label">Total Net Paid (KES)</div><div class="fsc-val">${totalNet.toLocaleString()}</div></div>
      <div class="fee-stat-card"><div class="fsc-label">Leave Records</div><div class="fsc-val">${lv.length}</div></div>
      <div class="fee-stat-card"><div class="fsc-label">Documents</div><div class="fsc-val">${docs.length}</div></div>`;
  }

  // ── Staff by Department ──
  const deptEl = document.getElementById('rptStaffByDept');
  if (deptEl) {
    const depts = {};
    staff.forEach(r=>{ depts[r.dept||'Unknown']=(depts[r.dept||'Unknown']||0)+1; });
    deptEl.innerHTML = rptBarChart(depts, staff.length, '#4f7cff');
  }

  // ── Staff by Status ──
  const statusEl = document.getElementById('rptStaffByStatus');
  if (statusEl) {
    const statuses = {};
    staff.forEach(r=>{ statuses[r.status||'Unknown']=(statuses[r.status||'Unknown']||0)+1; });
    const sc={Active:'#16a34a','On Leave':'#f59e0b',Resigned:'#ef4444',Retired:'#6b7280'};
    statusEl.innerHTML = rptBarChart(statuses, staff.length, null, sc);
  }

  // ── Payroll Summary ──
  const payEl = document.getElementById('rptPayrollSummary');
  if (payEl) {
    if (!pay.length) { payEl.innerHTML='<p style="color:var(--muted);font-size:.85rem">No payroll records yet.</p>'; }
    else {
      const totalBasic = pay.reduce((a,r)=>a+Number(r.basic||0),0);
      const totalAllow = pay.reduce((a,r)=>a+Number(r.allowances||0),0);
      const totalDed   = pay.reduce((a,r)=>a+Number(r.deductions||0),0);
      const totalNet2  = totalBasic+totalAllow-totalDed;
      const paid=pay.filter(r=>r.status==='Paid').length;
      payEl.innerHTML=`
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:.75rem;margin-bottom:1rem">
          ${[['Total Basic','KES '+totalBasic.toLocaleString(),'#4f7cff'],
             ['Total Allowances','KES '+totalAllow.toLocaleString(),'#16a34a'],
             ['Total Deductions','KES '+totalDed.toLocaleString(),'#ef4444'],
             ['Total Net Pay','KES '+totalNet2.toLocaleString(),'#7c3aed'],
             ['Paid Records',paid+' / '+pay.length,'#f59e0b']
            ].map(([l,v,c])=>`<div style="background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:.75rem 1rem">
              <div style="font-size:.78rem;color:var(--muted)">${l}</div>
              <div style="font-size:1.1rem;font-weight:700;color:${c}">${v}</div>
            </div>`).join('')}
        </div>`;
    }
  }

  // ── Documents by Type ──
  const docEl = document.getElementById('rptDocsByType');
  if (docEl) {
    if (!docs.length) { docEl.innerHTML='<p style="color:var(--muted);font-size:.85rem">No documents yet.</p>'; }
    else {
      const types={};
      docs.forEach(d=>{ types[d.type||'Other']=(types[d.type||'Other']||0)+1; });
      docEl.innerHTML = rptBarChart(types, docs.length, '#7c3aed');
    }
  }

  // ── Leave by Type ──
  const lvEl = document.getElementById('rptLeaveByType');
  if (lvEl) {
    if (!lv.length) { lvEl.innerHTML='<p style="color:var(--muted);font-size:.85rem">No leave records yet.</p>'; }
    else {
      const types={};
      lv.forEach(r=>{ types[r.type||'Other']=(types[r.type||'Other']||0)+1; });
      lvEl.innerHTML = rptBarChart(types, lv.length, '#f59e0b');
    }
  }
}

function rptBarChart(obj, total, defaultColor, colorMap) {
  const entries = Object.entries(obj).sort((a,b)=>b[1]-a[1]);
  if (!entries.length) return '<p style="color:var(--muted);font-size:.85rem">No data.</p>';
  return entries.map(([label,count])=>{
    const pct = total>0 ? Math.round((count/total)*100) : 0;
    const color = (colorMap&&colorMap[label]) || defaultColor || '#4f7cff';
    return `<div style="margin-bottom:.75rem">
      <div style="display:flex;justify-content:space-between;font-size:.85rem;margin-bottom:.3rem">
        <span style="font-weight:600">${label}</span>
        <span style="color:var(--muted)">${count} <span style="font-size:.75rem">(${pct}%)</span></span>
      </div>
      <div style="height:8px;background:var(--border);border-radius:4px;overflow:hidden">
        <div style="height:100%;width:${pct}%;background:${color};border-radius:4px;transition:width .5s ease"></div>
      </div>
    </div>`;
  }).join('');
}

/* ═══════════════════════════════════════════════════════
   ACCESS CONTROL LEVEL MANAGEMENT — Platform Admin
   ═══════════════════════════════════════════════════════ */

const AC_PRICING_KEY = 'ac_level_pricing';
const AC_LEVEL_NAMES = ['Basic','Standard','Advanced','Enterprise'];
const AC_LEVEL_COLORS = ['#3b82f6','#8b5cf6','#f59e0b','#ef4444'];
const AC_LEVEL_FEATURES = [
  ['Exam Analysis','Add Teachers','Add Students'],
  ['Exam Analysis','Add Teachers','Add Students','Timetable'],
  ['Exam Analysis','Add Teachers','Add Students','Timetable','Fees Management'],
  ['Exam Analysis','Add Teachers','Add Students','Timetable','Fees Management','Salary Management','Full Reports','System Settings']
];

function acLoadPricing() {
  try { return JSON.parse(localStorage.getItem(AC_PRICING_KEY)) || {}; } catch { return {}; }
}
function acSavePricingData(data) {
  localStorage.setItem(AC_PRICING_KEY, JSON.stringify(data));
}

function acInitPricing() {
  const stored = acLoadPricing();
  [0,1,2,3].forEach(i => {
    const inst = document.getElementById('acPrice'+i+'_install');
    const mon  = document.getElementById('acPrice'+i+'_monthly');
    if (!inst || !mon) return;
    if (stored['install_'+i] !== undefined) inst.value = stored['install_'+i];
    if (stored['monthly_'+i] !== undefined) mon.value  = stored['monthly_'+i];
    acUpdateAnnual(i);
  });
}

function acUpdateAnnual(i) {
  const mon = parseFloat(document.getElementById('acPrice'+i+'_monthly')?.value) || 0;
  const el  = document.getElementById('acPrice'+i+'_annual');
  if (el) el.textContent = 'KES ' + (mon * 12).toLocaleString();
}

function acSavePricing() {
  const data = {};
  [0,1,2,3].forEach(i => {
    data['install_'+i] = parseFloat(document.getElementById('acPrice'+i+'_install')?.value) || 0;
    data['monthly_'+i] = parseFloat(document.getElementById('acPrice'+i+'_monthly')?.value) || 0;
  });
  acSavePricingData(data);
  const msg = document.getElementById('acPriceSaveMsg');
  if (msg) { msg.innerHTML = '<i class="fa-solid fa-check" style="color:#22c55e"></i> Pricing saved'; setTimeout(()=>{ msg.textContent=''; }, 2500); }
}

function acShowLevelTab(idx) {
  [0,1,2,3].forEach(i => {
    const panel = document.getElementById('acLevelPanel'+i);
    const btn   = document.getElementById('acLevelTabBtn'+i);
    if (panel) panel.style.display = i===idx ? 'block' : 'none';
    if (btn) {
      if (i===idx) {
        btn.style.background = AC_LEVEL_COLORS[i];
        btn.style.color = '#fff';
        btn.style.borderColor = AC_LEVEL_COLORS[i];
        btn.className = 'btn btn-sm';
      } else {
        btn.style.background = '';
        btn.style.color = '';
        btn.style.borderColor = '';
        btn.className = 'btn btn-sm btn-outline';
      }
    }
  });
}

function acGetSchoolLevel(schoolId) {
  try {
    const map = JSON.parse(localStorage.getItem('ac_school_levels')) || {};
    return map[schoolId] !== undefined ? map[schoolId] : null;
  } catch { return null; }
}

function acSetSchoolLevel(schoolId, levelIdx) {
  try {
    const map = JSON.parse(localStorage.getItem('ac_school_levels')) || {};
    map[schoolId] = levelIdx;
    localStorage.setItem('ac_school_levels', JSON.stringify(map));
  } catch {}
}

function acGetSchoolActive(schoolId) {
  try {
    const map = JSON.parse(localStorage.getItem('ac_school_active')) || {};
    return map[schoolId] !== false;
  } catch { return true; }
}

function acToggleSchoolActive(schoolId) {
  try {
    const map = JSON.parse(localStorage.getItem('ac_school_active')) || {};
    map[schoolId] = !acGetSchoolActive(schoolId);
    localStorage.setItem('ac_school_active', JSON.stringify(map));
    acRenderSchoolList();
    acUpdateActiveSummary();
  } catch {}
}

function acActivateAll() {
  try {
    loadPlatform();
    const map = JSON.parse(localStorage.getItem('ac_school_active')) || {};
    platformSchools.forEach(s => { map[s.id] = true; });
    localStorage.setItem('ac_school_active', JSON.stringify(map));
    acRenderSchoolList();
    acUpdateActiveSummary();
    showToast('<i class="fa-solid fa-circle-check"></i> All schools activated', 'success');
  } catch {}
}

function acDeactivateAll() {
  if (!confirm('Deactivate ALL school subscriptions? Schools will lose access.')) return;
  try {
    loadPlatform();
    const map = JSON.parse(localStorage.getItem('ac_school_active')) || {};
    platformSchools.forEach(s => { map[s.id] = false; });
    localStorage.setItem('ac_school_active', JSON.stringify(map));
    acRenderSchoolList();
    acUpdateActiveSummary();
    showToast('<i class="fa-solid fa-circle-xmark"></i> All schools deactivated', 'error');
  } catch {}
}

function acUpdateActiveSummary() {
  try {
    loadPlatform();
    const total = platformSchools.length;
    const active = platformSchools.filter(s => acGetSchoolActive(s.id)).length;
    const el = document.getElementById('acActiveSummary');
    if (el) el.innerHTML = `<span style="color:#22c55e;font-weight:700">${active} active</span> <span style="color:var(--muted)">/ ${total} total</span>`;
  } catch {}
}

function acRenderSchoolList() {
  const el = document.getElementById('acSchoolList');
  if (!el) return;
  loadPlatform();
  const q = (document.getElementById('acSchoolSearch')?.value || '').toLowerCase();
  const schools = platformSchools.filter(s => !q || s.name.toLowerCase().includes(q));
  if (!schools.length) {
    el.innerHTML = '<p style="font-size:.85rem;color:var(--muted);padding:.5rem 0">No schools found. Add schools in the Schools tab first.</p>';
    acUpdateActiveSummary();
    return;
  }
  el.innerHTML = schools.map(s => {
    const lvl     = acGetSchoolLevel(s.id);
    const active  = acGetSchoolActive(s.id);
    const initials = s.name.split(' ').slice(0,2).map(w=>w[0]||'').join('').toUpperCase();
    const color   = lvl !== null ? AC_LEVEL_COLORS[lvl] : '#94a3b8';
    const levelBtns = AC_LEVEL_NAMES.map((n,i) =>
      `<button class="ac-lvl-btn ${lvl===i?'active-'+i:''}" onclick="acAssignLevel('${s.id}',${i})">${n}</button>`
    ).join('');
    const toggleLabel = active
      ? `<i class="fa-solid fa-toggle-on" style="color:#22c55e;font-size:1rem"></i> Active`
      : `<i class="fa-solid fa-toggle-off" style="color:#94a3b8;font-size:1rem"></i> Inactive`;
    const toggleStyle = active
      ? 'font-size:.72rem;font-weight:700;padding:.28rem .65rem;border-radius:6px;cursor:pointer;font-family:inherit;border:1.5px solid #22c55e;background:rgba(34,197,94,.08);color:#15803d;display:flex;align-items:center;gap:.3rem'
      : 'font-size:.72rem;font-weight:700;padding:.28rem .65rem;border-radius:6px;cursor:pointer;font-family:inherit;border:1.5px solid #ef4444;background:rgba(239,68,68,.07);color:#b91c1c;display:flex;align-items:center;gap:.3rem';
    return `<div class="ac-school-row" id="acRow-${s.id}" style="border-left:3px solid ${color}">
      <div class="ac-school-avatar" style="background:${color}">${initials}</div>
      <div class="ac-school-name">${s.name}<div style="font-size:.72rem;font-weight:400;color:var(--muted)">${s.username} · ${s.code||''}</div></div>
      <div class="ac-level-btns">${levelBtns}</div>
      <span class="ac-status-pill ${active?'ac-pill-on':'ac-pill-off'}">${active?'● Active':'○ Inactive'}</span>
      <button onclick="acToggleSchoolActive('${s.id}')" style="${toggleStyle}" title="${active?'Click to deactivate':'Click to activate'} access">
        ${toggleLabel}
      </button>
    </div>`;
  }).join('');
  acUpdateActiveSummary();
}


function acAssignLevel(schoolId, levelIdx) {
  acSetSchoolLevel(schoolId, levelIdx);
  acRenderSchoolList();
  const school = platformSchools.find(s=>s.id===schoolId);
  showToast(`<i class="fa-solid fa-layer-group"></i> <strong>${school?.name||schoolId}</strong> → ${AC_LEVEL_NAMES[levelIdx]} access assigned`, 'success');
}

function acDownloadLevelPDF(levelIdx) {
  const pricing = acLoadPricing();
  const lv = {
    name: AC_LEVEL_NAMES[levelIdx],
    color: AC_LEVEL_COLORS[levelIdx],
    features: AC_LEVEL_FEATURES[levelIdx],
    installation: pricing['install_'+levelIdx] || [5000,10000,20000,50000][levelIdx],
    monthly: pricing['monthly_'+levelIdx] || [2000,4000,7500,15000][levelIdx]
  };
  loadPlatform();
  const allFeats = ['Exam Analysis','Add Teachers','Add Students','Timetable','Fees Management','Salary Management','Full Reports','System Settings'];
  const featsHTML = allFeats.map(f=>{
    const has = lv.features.includes(f);
    return `<div style="display:flex;align-items:center;gap:8px;font-size:12px;padding:7px 10px;border-radius:6px;border:1px solid ${has?'#bbf7d0':'#e2e8f0'};background:${has?'#f0fdf4':'#f8fafc'};margin-bottom:5px">
      <span style="color:${has?'#16a34a':'#94a3b8'};font-size:15px;font-weight:700">${has?'✓':'✗'}</span>
      <span style="font-weight:${has?'700':'400'};color:${has?'#15803d':'#94a3b8'}">${f}</span>
      ${has?`<span style="margin-left:auto;font-size:10px;font-weight:700;padding:1px 7px;border-radius:20px;background:rgba(34,197,94,.15);color:#15803d">Included</span>`:`<span style="margin-left:auto;font-size:10px;color:#94a3b8">Not included</span>`}
    </div>`;
  }).join('');

  // Schools on this level
  const levelSchools = platformSchools.filter(s => acGetSchoolLevel(s.id) === levelIdx);
  const schoolRows = levelSchools.length ? levelSchools.map(s => {
    const active = acGetSchoolActive(s.id);
    return `<tr><td style="padding:7px 10px;font-weight:600;font-size:12px">${s.name}</td>
      <td style="padding:7px 10px;font-size:12px;color:#64748b">${s.username}</td>
      <td style="padding:7px 10px"><span style="font-size:11px;font-weight:700;padding:2px 9px;border-radius:20px;background:${active?'rgba(34,197,94,.12)':'rgba(239,68,68,.1)'};color:${active?'#15803d':'#b91c1c'}">${active?'● Active':'○ Inactive'}</span></td>
    </tr>`;
  }).join('') : `<tr><td colspan="3" style="padding:12px;text-align:center;color:#94a3b8;font-size:12px;font-style:italic">No schools assigned to this level</td></tr>`;

  const annual = lv.monthly * 12;
  const html = `<!DOCTYPE html><html><head><title>${lv.name} Level — SchoolPro Access Control</title>
  <style>body{font-family:Arial,sans-serif;margin:0;padding:28px 32px;color:#1e293b}@media print{.noprint{display:none}}</style></head>
  <body>
    <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:8px">
      <div>
        <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:${lv.color};margin-bottom:4px">Subscription Level ${levelIdx+1}</div>
        <h1 style="font-size:26px;font-weight:800;margin:0 0 2px">${lv.name}</h1>
        <div style="font-size:11px;color:#64748b">Generated: ${new Date().toLocaleDateString('en-KE',{year:'numeric',month:'long',day:'numeric'})}</div>
      </div>
      <button class="noprint" onclick="window.print()" style="background:${lv.color};color:#fff;border:none;padding:9px 20px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:700">🖨 Print / Save PDF</button>
    </div>
    <div style="height:4px;background:${lv.color};border-radius:2px;margin:12px 0 22px"></div>

    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:24px">
      <div style="border-radius:10px;padding:14px 16px;background:#f8fafc;border:1.5px solid #e2e8f0;text-align:center">
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:.06em;color:#64748b;margin-bottom:4px">Installation Fee</div>
        <div style="font-size:22px;font-weight:800;color:#1e293b">KES ${lv.installation.toLocaleString()}</div>
        <div style="font-size:10px;color:#94a3b8">one-time</div>
      </div>
      <div style="border-radius:10px;padding:14px 16px;background:#f8fafc;border:1.5px solid #e2e8f0;text-align:center">
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:.06em;color:#64748b;margin-bottom:4px">Monthly</div>
        <div style="font-size:22px;font-weight:800;color:#1e293b">KES ${lv.monthly.toLocaleString()}</div>
        <div style="font-size:10px;color:#94a3b8">per month</div>
      </div>
      <div style="border-radius:10px;padding:14px 16px;background:${lv.color}1a;border:1.5px solid ${lv.color}44;text-align:center">
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:.06em;color:#64748b;margin-bottom:4px">Annual</div>
        <div style="font-size:22px;font-weight:800;color:${lv.color}">KES ${annual.toLocaleString()}</div>
        <div style="font-size:10px;color:#94a3b8">per year</div>
      </div>
    </div>

    <h2 style="font-size:13px;text-transform:uppercase;letter-spacing:.06em;color:#334155;margin:0 0 10px">Feature Access</h2>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:5px;margin-bottom:24px">${featsHTML}</div>

    <h2 style="font-size:13px;text-transform:uppercase;letter-spacing:.06em;color:#334155;margin:0 0 10px">Schools on This Level (${levelSchools.length})</h2>
    <table style="width:100%;border-collapse:collapse;border:1.5px solid #e2e8f0;border-radius:8px;overflow:hidden">
      <thead><tr style="background:#f8fafc">
        <th style="padding:9px 10px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.04em">School Name</th>
        <th style="padding:9px 10px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.04em">Login</th>
        <th style="padding:9px 10px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.04em">Status</th>
      </tr></thead>
      <tbody>${schoolRows}</tbody>
    </table>
    <div style="margin-top:22px;font-size:10px;color:#94a3b8;text-align:center;border-top:1px solid #f1f5f9;padding-top:10px">SchoolPro Platform Admin — ${lv.name} Level Access Control Document — Confidential</div>
  </body></html>`;

  const w = window.open('','_blank','width=800,height=700');
  w.document.write(html);
  w.document.close();
  setTimeout(()=>w.focus(), 300);
}


function acDownloadPDF() {
  const pricing = acLoadPricing();
  const levelData = [0,1,2,3].map(i=>({
    name: AC_LEVEL_NAMES[i],
    color: AC_LEVEL_COLORS[i],
    features: AC_LEVEL_FEATURES[i],
    installation: pricing['install_'+i] || [5000,10000,20000,50000][i],
    monthly: pricing['monthly_'+i] || [2000,4000,7500,15000][i]
  }));
  loadPlatform();
  const schoolData = platformSchools.map(s=>({
    name: s.name,
    level: acGetSchoolLevel(s.id) !== null ? AC_LEVEL_NAMES[acGetSchoolLevel(s.id)] : 'Unassigned',
    levelIdx: acGetSchoolLevel(s.id),
    active: acGetSchoolActive(s.id)
  }));

  // Build printable HTML and open in new window for PDF
  const rows = levelData.map((lv,i) => {
    const allFeats = ['Exam Analysis','Add Teachers','Add Students','Timetable','Fees Management','Salary Management','Full Reports','System Settings'];
    const featsHTML = allFeats.map(f=>{
      const has = lv.features.includes(f);
      return `<div style="display:flex;align-items:center;gap:6px;font-size:11px;padding:5px 8px;border-radius:5px;border:1px solid ${has?'#bbf7d0':'#e2e8f0'};background:${has?'#f0fdf4':'#f8fafc'};margin-bottom:4px">
        <span style="color:${has?'#16a34a':'#94a3b8'};font-size:13px">${has?'✓':'✗'}</span>
        <span style="font-weight:${has?'600':'400'};color:${has?'#15803d':'#94a3b8'}">${f}</span>
      </div>`;
    }).join('');
    const annual = lv.monthly * 12;
    return `<div style="border:1.5px solid #e2e8f0;border-left:5px solid ${lv.color};border-radius:10px;padding:14px 16px;margin-bottom:14px;break-inside:avoid">
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
        <div style="width:32px;height:32px;border-radius:50%;background:${lv.color};display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;font-size:13px">L${i+1}</div>
        <div><div style="font-size:15px;font-weight:700">${lv.name}</div><div style="font-size:11px;color:#64748b">Level ${i+1}</div></div>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;margin-bottom:12px">${featsHTML}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;background:#f8fafc;border-radius:7px;padding:10px">
        <div style="text-align:center"><div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:.04em;margin-bottom:2px">Installation</div><div style="font-size:14px;font-weight:700;color:#1e293b">KES ${lv.installation.toLocaleString()}</div></div>
        <div style="text-align:center;border-left:1px solid #e2e8f0"><div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:.04em;margin-bottom:2px">Monthly</div><div style="font-size:14px;font-weight:700;color:#1e293b">KES ${lv.monthly.toLocaleString()}</div></div>
        <div style="text-align:center;border-left:1px solid #e2e8f0"><div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:.04em;margin-bottom:2px">Annual</div><div style="font-size:14px;font-weight:700;color:${lv.color}">KES ${annual.toLocaleString()}</div></div>
      </div>
    </div>`;
  }).join('');

  const schoolRows = schoolData.map(s=>{
    const c = s.levelIdx!==null ? AC_LEVEL_COLORS[s.levelIdx] : '#94a3b8';
    return `<tr style="border-bottom:1px solid #f1f5f9">
      <td style="padding:7px 10px;font-weight:600;font-size:12px">${s.name}</td>
      <td style="padding:7px 10px"><span style="background:${c}1a;color:${c};font-size:11px;font-weight:700;padding:2px 8px;border-radius:12px">${s.level}</span></td>
      <td style="padding:7px 10px"><span style="font-size:11px;font-weight:700;color:${s.active?'#16a34a':'#ef4444'}">${s.active?'Active':'Inactive'}</span></td>
    </tr>`;
  }).join('');

  const html = `<!DOCTYPE html><html><head><title>Access Level Control — SchoolPro</title>
  <style>body{font-family:Arial,sans-serif;margin:0;padding:24px;color:#1e293b}h1{font-size:20px;font-weight:700;margin-bottom:4px}h2{font-size:15px;font-weight:700;margin:18px 0 10px;color:#334155}@media print{.noprint{display:none}}</style></head>
  <body>
  <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px">
    <div><h1>SchoolPro — Access Level Control</h1><div style="font-size:11px;color:#64748b">Generated: ${new Date().toLocaleDateString('en-KE',{year:'numeric',month:'long',day:'numeric'})}</div></div>
    <button class="noprint" onclick="window.print()" style="background:#4f46e5;color:#fff;border:none;padding:8px 18px;border-radius:7px;cursor:pointer;font-size:13px;font-weight:700">🖨 Print / Save PDF</button>
  </div>
  <div style="height:3px;background:linear-gradient(90deg,#4f46e5,#10b981);border-radius:2px;margin:12px 0 18px"></div>
  <h2>Subscription Levels</h2>
  ${rows}
  <h2 style="margin-top:20px">School Assignments</h2>
  <table style="width:100%;border-collapse:collapse;border:1px solid #e2e8f0;border-radius:8px;overflow:hidden">
    <thead><tr style="background:#f8fafc"><th style="padding:8px 10px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.04em">School</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.04em">Level</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.04em">Status</th></tr></thead>
    <tbody>${schoolRows}</tbody>
  </table>
  <div style="margin-top:20px;font-size:10px;color:#94a3b8;text-align:center;border-top:1px solid #f1f5f9;padding-top:10px">SchoolPro Platform Admin — Confidential Access Control Document</div>
  </body></html>`;

  const w = window.open('','_blank','width=800,height=700');
  w.document.write(html);
  w.document.close();
  setTimeout(()=>w.focus(), 300);
}

